INSERT INTO public.photos VALUES (24885, 'Facultades de Medicina y Ciencias 1925', 'Se celebra en el actual Edificio Paraninfo el X Congreso Dental Espaâ”œâ–’ol, del 13 al 17 de septiembre de 1925. "Zaragoza. En la Facultad de Medicina y Ciencias. Asambleâ”œآ،stas y autoridades locales que concurrieron a la sesiâ”œâ”‚n inaugural del Congreso Dental Espaâ”œâ–’ol." Ocupâ”œâ”‚ la presidencia, en representaciâ”œâ”‚n del Gobierno, el gobernador civil, general Montero.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64736400, -0.88644100, '0101000020E610000054AC1A84B95DECBFCB4DD4D2DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14917486852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14917486852.webp', 'https://www.flickr.com/photos/zaragozaantigua/14917486852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24910, 'Instituto Anatâ”œâ”‚mico Forense 1988', 'Puerta de entrada del Instituto Anatâ”œâ”‚mico Forense Bastero Lerga, en la calle del Doctor Cerrada de Zaragoza, el 8 de septiembre de 1988. Fue inaugurado en 1908 en las traseras de la Facultad de Medicina y Ciencias, segâ”œâ•‘n proyecto de 1905 de Ricardo Magdalena. Consta de dos salas: la de Anatomâ”œآ،a y la Capilla. En 1968 se le aâ”œâ–’adiâ”œâ”‚ el nombre del mâ”œآ®dico legalista Juan Bastero Lerga. Se le denominaba popularmente "La Losa". Estuvo unido por un circuito cerrado de televisiâ”œâ”‚n con el aula de Medicina Legal, para que los alumnos contemplaran las autopsias. En julio de 2001 se trasladâ”œâ”‚ a la calle del Nuevo Parque del barrio de San Gregorio, con el nombre de Instituto de Medicina Legal de Aragâ”œâ”‚n. En lugar de cadâ”œأ­veres, hoy hay niâ”œâ–’os: en 2006 se abriâ”œâ”‚ allâ”œآ، la ludoteca infantil municipal El Chiflo. Fuente visual: "Memoria de las calles de Zaragoza", Juliâ”œأ­n Ruiz Marâ”œآ،n, Librerâ”œآ،a General, 1997.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.64744600, -0.88843300, '0101000020E610000048FDF50A0B6EECBF88F6B182DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21108545533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21108545533.webp', 'https://www.flickr.com/photos/zaragozaantigua/21108545533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24913, 'Facultad de Medicina 1933', 'Fachada principal de la Facultad de Medicina y Ciencias. A la izquierda, la Gran Vâ”œآ،a. A la derecha, el paseo de Pamplona. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64751700, -0.88611700, '0101000020E61000008CBFED09125BECBF514D49D6E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22616414923.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22616414923.webp', 'https://www.flickr.com/photos/zaragozaantigua/22616414923/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
