INSERT INTO public.photos VALUES (24711, 'Chabolismo 1993', 'Imagen capturada en la zona sin urbanizar delimitada entre las calles de Paulino Savirâ”œâ”‚n y del Monasterio del Escorial, en el barrio de Las Fuentes, y motivada por episodios de chabolismo e infravivienda. Al fondo, traseras de la antigua fâ”œأ­brica de CEFA, y la emergente y caracterâ”œآ،stica torre que remataba los Talleres Diesel Zaragoza sitos en la calle de Miguel Servet.', 1993, 1993, 1993, 'Anos 90', 'LAS FUENTES', 41.63797700, -0.86158900, '0101000020E6100000ADFC32182392EBBFD34CF73AA9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450146138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450146138.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450146138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24920, 'Paraninfo 2005', 'Ilustraciâ”œâ”‚n de Marta Martâ”œآ،nez Garcâ”œآ،a para la revista Maszoom, 2005. Representa los pâ”œآ®treos sillones adosados a las pilastras de la portada del Paraninfo de la Universidad de Zaragoza, antigua Facultad de Medicina y Ciencias (Ricardo Magdalena, 1893), en la plaza de Basilio Paraâ”œآ،so 4. Los personajes sedentes originales son el mâ”œآ®dico y filâ”œâ”‚sofo turolense Andrâ”œآ®s Piquer (1711-1772); el cientâ”œآ،fico y teâ”œâ”‚logo oscense Miguel Servet (1509-1553); el naturalista y jurista zaragozano Jordâ”œأ­n de Asso (1742-1814); y el quâ”œآ،mico e ingeniero logroâ”œâ–’â”œآ®s Fausto Delhuyar (1755-1833), descubridor del wolframio. Las estatuas de los extremos son obra de Jaime Lluch, y las centrales de Dionisio Lasuâ”œآ®n. En el dibujo, el ilustrado Andrâ”œآ®s Piquer luce un disfraz de (o es sustituido por) Spider-Man, personaje de câ”œâ”‚mic creado en 1962 por el neoyorquino Stan Lee. Fuente visual: martamartinezgarcia.blogspot.com', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.64743500, -0.88657900, '0101000020E610000096404AECDA5EECBF94A46B26DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32789968770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32789968770.webp', 'https://www.flickr.com/photos/zaragozaantigua/32789968770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24971, 'Motociclismo 1948', 'Foto: Valero Echegoyen. En junio de 1948 se celebrâ”œâ”‚ la primera carrera de motos de velocidad de Zaragoza, en un circuito urbano entre la Maternidad (en el paseo de Marâ”œآ،a Agustâ”œآ،n) y la Facultad de Medicina y Ciencias. En la foto, tres de los participantes pasan por delante de la Facultad, en el paseo de Pamplona. Fuente visual: cincodays.com/2015/02/25/siempre-ocurren-cosas-1923/', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.64766100, -0.88624500, '0101000020E6100000EACA67791E5CECBF84F23E8EE6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18965587720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18965587720.webp', 'https://www.flickr.com/photos/zaragozaantigua/18965587720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24986, 'Paseo de Pamplona 1934', 'Paso de los miembros del Club Ciclista Ebro por el paseo de Pamplona en 1934, a su llegada a lo que serâ”œأ­ la plaza de Paraâ”œآ،so. Este club deportivo fue fundado en 1933, con sede en la calle de Jesâ”œâ•‘s 1, bajos. Al fondo, monumento a la Exposiciâ”œâ”‚n Hispano-Francesa de 1908, trasladado al parque Primo de Rivera en 1951. Fuente: www.clubciclistaebro.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64804400, -0.88620400, '0101000020E610000046B3B27DC85BECBF3C2F151BF3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32873534626.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32873534626.webp', 'https://www.flickr.com/photos/zaragozaantigua/32873534626/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24989, 'P.â”¬â•‘ de Sagasta 1916', 'Imagen capturada durante la â”œâ•‘ltima prueba ciclista celebrada en el Velâ”œâ”‚dromo de los Campos Elâ”œآ،seos, organizada por el zaragozano club Velo-Sport Aragonâ”œآ®s (fundado en 1915) durante las fiestas mayores de la poblaciâ”œâ”‚n de ese aâ”œâ–’o, en el circuito sito en el arranque del paseo de Sagasta (nâ”¬â•‘ 2). En el posado, corredores como Puyol, Martâ”œآ،nez, y Jou. Fuente visual: www.mecd.gob.es/.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64638100, -0.88605700, '0101000020E6100000378AAC35945AECBFBDE0D39CBCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35506860422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35506860422.webp', 'https://www.flickr.com/photos/zaragozaantigua/35506860422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25041, 'Vista del sureste 1893', 'Extraordinaria imagen capturada desde la altura del torreâ”œâ”‚n del nuevo edificio de las Facultades de Medicina y Ciencias de la Universidad de Zaragoza. La vista estâ”œأ­ orientada hacia el sureste de la ciudad, una zona que tras el puente de Santa Engracia se vertebraba por el camino de Torrero/paseo de Sagasta, el paseo de las Damas y el camino de las Torres, con un urbanismo disperso y de muy baja densidad. En primer tâ”œآ®rmino, y tras el râ”œآ،o Huerva, una de las escasas imâ”œأ­genes datadas del circo de los Campos Elâ”œآ،seos, construido con materiales sencillos en 1889 donde antes estuviera el efâ”œآ،mero Teatro de los Campos Elâ”œآ،seos, clausurado sobre 1880. Este circo descubierto era tambiâ”œآ®n utilizado como ocasional plaza de toros, y su vida activa tambiâ”œآ®n fue breve, pues en 1895 aquâ”œآ، se construirâ”œآ،a un velâ”œâ”‚dromo, tambiâ”œآ®n denominado de los Campos Elâ”œآ،seos. Tras â”œآ®l, el recoleto acceso a la fâ”œأ­brica de camas de hierro y latâ”œâ”‚n de Miguel Irisarri Lâ”œâ”‚pez, donde destaca uno de los carros tirados por caballerâ”œآ،a para transporte del gâ”œآ®nero producido. Detrâ”œأ­s y arbolado, el camino de Torrero asciende entre un panorama poco urbanizado, entre el Huerto y Torre de Val, la Huerta de los Jesuitas, y la Torre de Garcâ”œآ،a Gil. Por entre la arboleda, a la derecha, emerge como desde 1873 la fundiciâ”œâ”‚n de Martâ”œآ،n Rodâ”œâ”‚n y Hermano, y el colegio del Sagrado Corazâ”œâ”‚n, que flaquean el principio del paseo de las Damas. Al fondo, panorama de Miraflores hasta las primeras terrazas que anuncian el ascenso hacia Torrero. Por una de ellas serpentea arbolado el camino de las Alcachoferas. Al fondo y a la derecha se destaca la neoclâ”œأ­sica câ”œâ•‘pula de la iglesia de San Fernando, inmersa en los cuarteles de Torrero.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64641200, -0.88600800, '0101000020E6100000DDD1FF722D5AECBFF8DEDFA0BDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47391510242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47391510242.webp', 'https://www.flickr.com/photos/zaragozaantigua/47391510242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25091, 'Torrebruno 1964', 'El cantante italiano Rocco Torrebruno (1936-1998) fue invitado a un programa de Radio Juventud (desde 1978, Radiocadena Espaâ”œâ–’ola) conducido por Enrique Calvo, en 1964. Al aâ”œâ–’o siguiente, Torrebruno presentarâ”œآ،a el concierto de The Beatles en Madrid. En la foto, acompaâ”œâ–’ado de unas admiradoras, en la sede radiofâ”œâ”‚nica del paseo Calvo Sotelo 7. Fuente visual: Colecciâ”œâ”‚n particular.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.64655800, -0.88636100, '0101000020E610000038656EBE115DECBFCC7B9C69C2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32586123221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32586123221.webp', 'https://www.flickr.com/photos/zaragozaantigua/32586123221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25236, 'Ricardo Magdalena c.1900', 'Archivo de la Escuela de Artes y Oficios de Zaragoza, entre 1895 y 1908. El arquitecto Ricardo Magdalena (1849-1910) en una de sus clases en la Escuela de Artes y Oficios de Zaragoza, ubicada en la antigua Facultad de Medicina y Ciencias desde 1895. Tras la exposiciâ”œâ”‚n Hispano-Francesa de 1908, esta escuela serâ”œآ،a reubicada en el pabellâ”œâ”‚n de las Escuelas del recinto ferial. Fuente visual: "Ricardo Magdalena. Arquitecto municipal de Zaragoza". IFC, 2012.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64719400, -0.88688000, '0101000020E6100000533F6F2A5261ECBF6E15C440D7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15540473071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15540473071.webp', 'https://www.flickr.com/photos/zaragozaantigua/15540473071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25237, 'Pl. de Basilio Paraâ”œآ،so 1954', 'Imagen centrada en la Facultad de Medicina y Ciencias, lugar de celebraciâ”œâ”‚n del XV Congreso de Esperanto, y en el arranque de un paseo de Pamplona aâ”œâ•‘n con paseo central. Una composiciâ”œâ”‚n de la Lâ”œآ،nea 5, camino de Torrero, y un BUT de 1 piso, viene de Terminillo. El nâ”¬â•‘ 1 del paseo de Pamplona y su chaflâ”œأ­n y remate acristaladado con Doctor Cerrada, llegarâ”œآ،a en 1958. El parque motorizado de la ciudad aâ”œâ•‘n era sostenible. Fuente visual: www.bildarchivaustria.at/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64793500, -0.88637300, '0101000020E610000049D6E1E82A5DECBF8577B988EFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16037059376.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16037059376.webp', 'https://www.flickr.com/photos/zaragozaantigua/16037059376/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25238, 'Puerta de Santa Engracia 1891', 'Imagen, de autorâ”œآ،a anâ”œâ”‚nima, de la Tercera Puerta de Santa Engracia desde la Glorieta de Pignatelli, con visual de la inacabada Facultad de Medicina y Ciencias de la Universidad. En marzo de 1887 se habâ”œآ،a puesto la primera piedra al proyecto de Ricardo Magdalena sobre lo que hasta entonces era el campo de Lezcano, y un lustro despuâ”œآ®s la obra serâ”œآ،a culminada, si bien la inauguraciâ”œâ”‚n oficial se postergâ”œâ”‚ a octubre de 1893. En la imagen, el recinto aâ”œâ•‘n estâ”œأ­ rodeado por la valla de obra y, a la izquierda, el pretil del puente de Santa Engracia sobre el Huerva estâ”œأ­ aâ”œâ•‘n sin terminar. Al fondo, el olivar y la Torre de Fita. A la derecha, huertos y torres del antiguo Camino de Herederos, o de los Cubos. Un afiche sobre la Puerta de Santa Engracia anuncia un prâ”œâ”‚ximo concierto en el "Teatro-Circo" de la "Sociedad de Conciertos de Madrid", la principal orquesta madrileâ”œâ–’a, que anunciaba con orgullo estar compuesta por 100 "profesores", dirigidos en esa â”œآ®poca por el maestro Tomâ”œأ­s Bretâ”œâ”‚n. Fuente: amable aporte de Josâ”œآ® Luis Cintora.', 1891, 1891, 1891, 'Siglo XIX', 'CENTRO', 41.64736400, -0.88644100, '0101000020E610000054AC1A84B95DECBFCB4DD4D2DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17139069988.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17139069988.webp', 'https://www.flickr.com/photos/zaragozaantigua/17139069988/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25241, 'P.â”¬â•‘ de Pamplona 1957', 'En setiembre de 1953 fue firmado el "Joint U.S.-Spanish Military Group", por el que el Gobierno de Espaâ”œâ–’a autorizaba a las Fuerzas Aâ”œآ®reas de los EEUU de Norteamâ”œآ®rica (USAF) el uso, entre otras, de la base aâ”œآ®rea de Zaragoza. Asâ”œآ،, entre marzo de 1956 y setiembre de 1957 la superficie de Espaâ”œâ–’a fue capturada en una serie de vuelos fotogramâ”œآ®ticos de cartografâ”œآ،a militar, en el contexto de la "Guerra Frâ”œآ،a", y Espaâ”œâ–’a incorporada al nuevo Eje anticomunista. Segâ”œâ•‘n testimonios de los pilotos norteamericanos, el paâ”œآ،s que se encontraron a sus pies "parecâ”œآ،a igual que en los primeros aâ”œâ–’os 30". En la imagen, cortesâ”œآ،a de las USAF, aâ”œآ®rea visual del arranque del paseo de Pamplona desde la plaza de Paraâ”œآ،so, cuando aâ”œâ•‘n conservaba el provinciano bulevar central ajardinado y peatonal. En Hernâ”œأ­n Cortâ”œآ®s, despunta el escalonado remate del colegio de las "Adoratrices Esclavas del Santâ”œآ،simo y de la Caridad", y en la zona de la Puerta del Carmen aâ”œâ•‘n perduran las huertas del antiguo Convento de la Encarnaciâ”œâ”‚n.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64790200, -0.88634200, '0101000020E61000008847E2E5E95CECBFAA81E673EED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21955200930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21955200930.webp', 'https://www.flickr.com/photos/zaragozaantigua/21955200930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25251, 'Calle Doctor Cerrada 1956', 'Entrada de la calle del Doctor Cerrada en marzo de 1956. A la derecha, paseo de Pamplona, cuyo edificio del nâ”œâ•‘mero 3 se ve, merced a la ausencia de edificaciâ”œâ”‚n en el nâ”œâ•‘mero 1. Al fondo a la izquierda, fachadas traseras de la calle de Almagro; en la izquierda, esquina de la valla de la Facultad de Medicina y Ciencias. Fuente: Foto Câ”œآ®sar Châ”œâ”‚liz.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64795900, -0.88687700, '0101000020E61000000F63D2DF4B61ECBF0E130D52F0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31023451523.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31023451523.webp', 'https://www.flickr.com/photos/zaragozaantigua/31023451523/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25255, 'Pl. de Paraâ”œآ،so c.1955', 'Nocturna y despejada imagen capturada en el arranque del paseo de Pamplona, con el panorama de la plaza de Basilio Paraâ”œآ،so. Inmediato a la derecha, un pedazo del desaparecido andador central del paseo, donde se encontrara el monumento a la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. Detrâ”œأ­s, la facultad de Medicina y Ciencias. Focaliza la imagen el emblemâ”œأ­tico edificio Elâ”œآ،seos, y su luminosa peineta publicitaria, entre el paseo de Calvo Sotelo, y el del General Mola. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64767600, -0.88616000, '0101000020E61000005DBF60376C5BECBFB933130CE7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33413157800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33413157800.webp', 'https://www.flickr.com/photos/zaragozaantigua/33413157800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25256, 'Vista 1895', 'Interesante imagen capturada desde la altura del torreâ”œâ”‚n del nuevo edificio de las Facultades de Medicina y Ciencias de la Universidad de Zaragoza. La vista estâ”œأ­ orientada hacia el septentriâ”œâ”‚n de la ciudad. En primer tâ”œآ®rmino y a la izquierda, la frondosidad del paseo de la Lealtad flanqueado hasta por tres lavaderos en el tramo entre el camino de los Cubos y el paseo de los Capuchinos, y entre la calle de Teruel y la de la Soberanâ”œآ،a Nacional. A la derecha, el edificio de la nueva Capitanâ”œآ،a General junto a la calle de Valencia, y tras â”œآ®l las dos bizarras cupulillas que remataban el inmueble del nâ”¬â•‘ 10 de la glorieta de Pignatelli, diseâ”œâ–’ado por Fernando de Yarza. En el centro de la imagen, tras el torreâ”œâ”‚n norte del edificio de las Facultades de Medicina y Ciencias, despunta la basilical estructura de la novâ”œآ،sima iglesia del colegio de las Esclavas del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, esquinera entre la calle de Teruel y la de Canfranc. Por encima se destaca la rotunda estructura del cuartel de artillerâ”œآ،a del Carmen y la iglesia entonces denominada del Sagrado Corazâ”œâ”‚n, o de San Ildefonso, con andamios de obra sobre la sufrida câ”œâ•‘pula, aâ”œâ•‘n en obras tras la devastaciâ”œâ”‚n producida por el rayo caâ”œآ،do en 1860. A su derecha emergen los torreones laterales de la Audiencia Territorial; las torres y câ”œâ•‘pula de la iglesia de Santa Isabel de Portugal; la câ”œâ•‘pula de la barroca iglesia de la Manterâ”œآ،a de las madres Escolapias; y la torrecilla de la iglesia de San Felipe y Santiago. A su lado, el vacâ”œآ،o dejado por el reciente derribo de la Torre Nueva todavâ”œآ،a llama la atenciâ”œâ”‚n. Finalmente, el colofâ”œâ”‚n del templo metropolitano del Pilar, con su â”œâ•‘nica torre de Santiago reciâ”œآ®n coronada con el chapitel metâ”œأ­lico forjado en los talleres Averly y diseâ”œâ–’ado por el arquitecto Ricardo Magdalena. A sus pies, las originales câ”œâ•‘pulas de media naranja que remataban la nueva manzana de casas en la plaza del Pilar, esquina a la calle de Alfonso I, propiedad del marquâ”œآ®s de Ayerbe.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64775900, -0.88688800, '0101000020E610000009E066F16261ECBF475854C4E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33580751038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33580751038.webp', 'https://www.flickr.com/photos/zaragozaantigua/33580751038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25262, 'Vista 1891', 'Singular fotografâ”œآ،a realizada desde la altura del torreâ”œâ”‚n en construcciâ”œâ”‚n del nuevo edificio de las Facultades de Medicina y Ciencias de la Universidad de Zaragoza. La aterrazada culminaciâ”œâ”‚n de este torreâ”œâ”‚n estaba previsto que acogiera un observatorio astronâ”œâ”‚mico. En primer tâ”œآ®rmino, vista parcial del patio central con la estructura de madera que seâ”œâ–’ala la construcciâ”œâ”‚n del gran aulario de planta semicircular de la Facultad de Ciencias. La singularidad de esta imagen se incrementa con la casual vista que al fondo nos ofrece un panorama de atalayas y referencias edilicias en altura de la ciudad, que de izquierda a derecha nos muestra el Hospital Provincial, la torre de la iglesia de San Pablo Apâ”œâ”‚stol, la câ”œâ•‘pula de San Ildefonso, la Torre Nueva desmochada de su chapitel y antes de su derribo, el templo del Pilar con su â”œâ•‘nica torre, de Santiago, sin finalizar. Finalmente, y casi imperceptible, el remate de la torre de la Seo.', 1891, 1891, 1891, 'Siglo XIX', 'CENTRO', 41.64735800, -0.88700600, '0101000020E610000084622B685A62ECBFE8667FA0DCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50248565866.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50248565866.webp', 'https://www.flickr.com/photos/zaragozaantigua/50248565866/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24712, 'Calle de San Adriâ”œأ­n de Sasabe 1991', 'Imagen capturada en las traseras de la barriada "Vizconde de Escoriaza" acompaâ”œâ–’ando a unos vecinos por la calle de San Adriâ”œأ­n de Sasabe, que en este tramo apenas resultaba ser un camino de paso entre el grupo de viviendas y la cercana huerta. Mâ”œأ­s tarde esta calle serâ”œآ،a notablemente ensanchada y urbanizada, y recientemente ha surgido una zona de neo huerta donde estuviera la de toda la vida. Al fondo sobresalen los grandes bloques esquineros con la calle de Rudesindo Nasarre.', 1991, 1991, 1991, 'Anos 90', 'LAS FUENTES', 41.64844800, -0.85777000, '0101000020E61000006DAD2F12DA72EBBF0C94145800D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450530071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450530071.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450530071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25263, 'Vista 1893', 'Imagen capturada desde la altura del torreâ”œâ”‚n-observatorio meteorolâ”œâ”‚gico del nuevo edificio de las Facultades de Medicina y Ciencias de la Universidad tras la terminaciâ”œâ”‚n efectiva de las obras de construcciâ”œâ”‚n. La vista estâ”œأ­ orientada hacia el septentriâ”œâ”‚n de la ciudad, levemente escorada hacia el este. Centra la escena y en primer tâ”œآ®rmino, el edificio del "Nuevo Palacio para Capitanâ”œآ،a general de Aragâ”œâ”‚n" delimitado entre la calle de Valencia, la glorieta de Pignatelli y el arranque del paseo de la Lealtad. A la derecha, los orientales hotelitos de los nâ”œâ•‘meros 1 a 4 de la glorieta, con una muestra de su aspecto casi original, destacando los seriados 1 a 3, luego bastante modificados. Junto a ellos, el Teatro Pignatelli, y por encima del nâ”¬â•‘ 1 emerge la entonces â”œâ•‘nica torre de la iglesia parroquial de Santa Engracia. Al fondo y a la izquierda, el templo metropolitano del Pilar con su â”œâ•‘nica torre de Santiago reciâ”œآ®n coronada con el chapitel metâ”œأ­lico forjado en los talleres Averly y diseâ”œâ–’ado por el arquitecto Ricardo Magdalena. Hacia la derecha emergen del caserâ”œآ،o la torre de San Gil Abad, la torre y cimborrio de la Seo, la torre de Santa Marâ”œآ،a Magdalena, y la torre de San Carlos Borromeo-seminario sacerdotal.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64745400, -0.88668400, '0101000020E6100000EA5DBC1FB75FECBF0BD5CDC5DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50253576958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50253576958.webp', 'https://www.flickr.com/photos/zaragozaantigua/50253576958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25264, 'Facultad de Medicina 1895', 'Dibujo centrado en la fachada del edificio de las Facultades de Medicina y Ciencias de la Universidad de Zaragoza construido con proyecto del arquitecto Ricardo Magdalena Tabuenca frente a la Puerta de Santa Engracia, que daba su nombre a este espacio. Como el dibujante no se desplazâ”œâ”‚ a Zaragoza para capturar el instante, se inspirâ”œâ”‚ en la fotografâ”œآ،a de este edificio publicada en 1894 en "Edificio para las Facultades de Medicina y Ciencias en Zaragoza" (Enrique Marâ”œآ،a Repullâ”œآ®s y Vargas, Madrid) que en forma de postal fue editada por la casa Hauser y Menet (Madrid) como una de las instantâ”œأ­neas zaragozanas incluidas en su serie general de postales de Espaâ”œâ–’a. A la izquierda del edificio quedaba el puente de Santa Engracia sobre el râ”œآ،o Huerva, y hacia la derecha comenzaba el paseo de la Lealtad. En 1910 este despejado espacio recibiâ”œâ”‚ el nombre de plaza de don Basilio Paraâ”œآ،so como homenaje a este prâ”œâ”‚cer local coincidiendo con la inauguraciâ”œâ”‚n del monumento a la Exposiciâ”œâ”‚n hispanofrancesa de 1908 instalado al principio del paseo de Pamplona (antiguo de la Lealtad). El carro de la izquierda nos recuerda que entonces por aquâ”œآ، transitaban los coches del tranvâ”œآ،a a propulsiâ”œâ”‚n de sangre adscritos a la lâ”œآ،nea de Torrero que conectaba la plaza de la Constituciâ”œâ”‚n con la playa de Torrero junto al cuartel de los Castillejos.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64752600, -0.88623400, '0101000020E6100000F04DD367075CECBFA4A7C821E2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53234737027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53234737027.webp', 'https://www.flickr.com/photos/zaragozaantigua/53234737027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25265, 'Câ”¬â•‘. de los Cubos 1895', 'Dibujo centrado en la fachada recayente al camino de los Cubos del edificio de las Facultades de Medicina y Ciencias de la Universidad de Zaragoza construido con proyecto del arquitecto Ricardo Magdalena Tabuenca. Como el dibujante francâ”œآ®s que realizâ”œâ”‚ esta imagen no se desplazâ”œâ”‚ a Zaragoza para capturar el instante, se inspirâ”œâ”‚ en la fotografâ”œآ،a de este edificio publicada en 1894 en "Edificio para las Facultades de Medicina y Ciencias en Zaragoza" (Enrique Marâ”œآ،a Repullâ”œآ®s y Vargas, Madrid) y que en forma de postal fue editada por la casa Hauser y Menet (Madrid) como una de las instantâ”œأ­neas zaragozanas incluidas en su serie general de postales de Espaâ”œâ–’a. Segâ”œâ•‘n el proyecto del edificio, en esta zona se encontraba (de izquierda a derecha) el laboratorio general de Fâ”œآ،sica; el gabinete de Fâ”œآ،sica; los laboratorios para profesores; el gabinete de Mecâ”œأ­nica y Fâ”œآ،sica; y la câ”œأ­tedra de conferencias. Las sombras que sobre el suelo se proyectan en primer tâ”œآ®rmino y hacia la derecha se corresponden con los pabellones de las clâ”œآ،nicas universitarias.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64750200, -0.88750000, '0101000020E6100000666666666666ECBF1C0C7558E1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53246286695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53246286695.webp', 'https://www.flickr.com/photos/zaragozaantigua/53246286695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25266, 'Puerta de Santa Engracia c.1900', 'Imagen capturada a espaldas de la Puerta de Santa Engracia (a la derecha, pilastra de su ingreso mâ”œأ­s occidental) y orientada en este caso hacia la fachada del edificio que acogâ”œآ،a a las facultades de Medicina y Ciencias de la Universidad de Zaragoza, y temporalmente a la Escuela de Artes y Oficios. Sobre el firme, vâ”œآ،as de la lâ”œآ،nea de Torrero. Hacia la derecha, inicio del paseo de la Lealtad.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64751800, -0.88616900, '0101000020E61000002A5437177F5BECBF21C9ACDEE1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54624724462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54624724462.webp', 'https://www.flickr.com/photos/zaragozaantigua/54624724462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26012, 'Vista aâ”œآ®rea Paraninfo 1986', 'Foto: Josâ”œآ® Luis Pomarâ”œâ”‚n Vista aâ”œآ®rea del entorno de la antigua Facultad de Medicina y CIencias. Abajo, la plaza de Paraâ”œآ،so. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.64727500, -0.88691100, '0101000020E610000014CE6E2D9361ECBF5B423EE8D9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22327688811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22327688811.webp', 'https://www.flickr.com/photos/zaragozaantigua/22327688811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26045, 'Pâ”¬â•‘ de Pamplona 1963', 'Vista aâ”œآ®rea con el entorno de la plaza de Paraâ”œآ،so desde el remodelado para el trâ”œأ­fico rodado paseo de Pamplona, a la derecha. A la izquierda, la plaza de Aragâ”œâ”‚n y sus hotelitos. Desde la plaza de Paraâ”œآ،so, acceso al colegio del Salvador y su reciente iglesia, y arranque de la avenida de Marina Moreno, y de los paseos de las Damas, del General Mola, y de Calvo Sotelo. Inmediata, la calle de Canfranc conecta la plaza de Aragâ”œâ”‚n con el paseo de Pamplona, y nos ofrece una interesante imagen de conjunto del convento e iglesia de las Esclavas del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s, en la confluencia con la calle de Bilbao, derribado unos aâ”œâ–’os despuâ”œآ®s. Enfrente, el colegio de "La Enseâ”œâ–’anza" de la Compaâ”œâ–’â”œآ،a de Marâ”œآ،a. Fuente visual: Arxiu Nacional de Catalunya.', 1963, 1963, 1963, 'Anos 60', 'CENTRO', 41.64805700, -0.88598600, '0101000020E6100000E9D7D64FFF59ECBFD1782288F3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31618217382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31618217382.webp', 'https://www.flickr.com/photos/zaragozaantigua/31618217382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25392, 'Plaza del Mercado 1884', '"Eine Straâ”œئ’e in Zaragoza", ilustraciâ”œâ”‚n de 1884 en una publicaciâ”œâ”‚n en alemâ”œأ­n. Se observa "una calle en Zaragoza" con actividad comercial, y los pâ”œâ”‚rticos de la plaza del Mercado al fondo. Fuente: www.facebook.com/photo.php?fbid=10203272077522554&set...', 1884, 1884, 1884, 'Siglo XIX', 'CENTRO', 41.65584600, -0.88272600, '0101000020E61000005186AA984A3FECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19430291309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19430291309.webp', 'https://www.flickr.com/photos/zaragozaantigua/19430291309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20950, 'Puerta Quemada ca. 1800', '"Puerta Quemada", Antonio Callaved, 2010. Reconstrucciâ”œâ”‚n idealizada de la sencilla puerta en la muralla medieval, al final de la actual calle del Heroâ”œآ،smo, en su encuentro con la ribera del râ”œآ،o Huerva. Destruida en 1808. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1800, 1800, 1800, 'Siglo XIX', 'CENTRO', 41.64921500, -0.87497000, '0101000020E61000005665DF15C1FFEBBF4C89247A19D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15092325899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15092325899.webp', 'https://www.flickr.com/photos/zaragozaantigua/15092325899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20961, 'Jardâ”œآ،n Botâ”œأ­nico 1853', 'Una de las iniciativas de la "Real Sociedad Econâ”œâ”‚mica de Amigos del Paâ”œآ،s" fue establecer un "Jardâ”œآ،n experimental" en el que se conjugar la posibilidad de plantar especies vegetales exâ”œâ”‚ticas y nativas, y establecer un aulario de botâ”œأ­nica. Se arrendâ”œâ”‚ unos terrenos cercanos a la plaza de San Miguel, cerca de las monjas de Santa Catalina, se habilitâ”œâ”‚ el terreno, y se construyeron aulas para casi 50 alumnos. Fue inaugurado en 1778, pero en 1808 quedâ”œâ”‚ destruido por su cercanâ”œآ،a al Convento-Fuerte de San Josâ”œآ®. Despuâ”œآ®s de 1813 se hicieron intentos por recuperarlo, y en 1843 se traspasâ”œâ”‚ su gestiâ”œâ”‚n a la Universidad. Hacia 1860 se extendâ”œآ،a por 3800 m2, con 1500 especies de plantas, riego del Canal Imperial, buena visual de las afueras de la ciudad, entrada por la calle de San Miguel nâ”¬â•‘ 30, y visitable. La progresiva urbanizaciâ”œâ”‚n del entorno de la plaza de Castelar tras la Expo de 1908, condujeron al "traslado" provisional del Botâ”œأ­nico, en 1923, a terrenos anexos al nuevo edificio de Medicina y Ciencias. En la dâ”œآ®cada siguiente fue nuevamente trasladado a unos amplios espacios en el paseo de Ruiseâ”œâ–’ores, donde poco despuâ”œآ®s serâ”œأ­ construido el nuevo y femenino Instituto "Miguel Servet". Allâ”œآ، estuvo hasta que en 1970 es trasladado al parque Primo de Rivera, en donde permanece. En la imagen, el "Jardâ”œآ،n experimental" durante su estancia en la calle de San Miguel. El Plano utilizado es de 1853, de Francisco Coello, por eso la plaza de la Constituciâ”œâ”‚n ya aparece, asâ”œآ، como el ancho "paseo interior de Santa Engracia". Fuente: "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o XXXII, Nâ”¬â•‘ 247, abril-junio 1958).', 1853, 1853, 1853, 'Siglo XIX', 'CENTRO', 41.64993900, -0.87839100, '0101000020E61000003B394371C71BECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15508095369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15508095369.webp', 'https://www.flickr.com/photos/zaragozaantigua/15508095369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20995, 'Puerta del Duque 1856', '"Puerta que el Excelentâ”œآ،simo Ayuntamiento constitucional de Zaragoza dedica al Excelentâ”œآ،simo Seâ”œâ–’or Duque de la Victoria". Miguel Jeliner y Germâ”œأ­, 17 de febrero de 1856. Alzado de la Puerta del Duque en 1856. Se levantâ”œâ”‚ junto a la iglesia de San Miguel. Poco despuâ”œآ®s de derrumbâ”œâ”‚, y fue sustituida en 1861 por una nueva, diseâ”œâ–’ada por Josâ”œآ® de Yarza. Fuente: AMZ.', 1856, 1856, 1856, 'Siglo XIX', 'CENTRO', 41.64951900, -0.87615100, '0101000020E61000003F726BD26D09ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32045520971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32045520971.webp', 'https://www.flickr.com/photos/zaragozaantigua/32045520971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21049, 'San Miguel c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œآ،a. 1872-1879. Iglesia de San Miguel.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64963500, -0.87651300, '0101000020E6100000679AB0FD640CECBF22AB5B3D27D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679653787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679653787.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679653787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21075, 'San Miguel c.1877', 'Todo el "aire" alrededor del cuadro seleccionado por Laurent y Câ”œآ،a para editar la producida imagen final, amplâ”œآ،a el foco, y aâ”œâ–’ade una muy interesante panorâ”œأ­mica de la antigua plaza de San Miguel, tanto por los elementos de la izquierda (engarce con la puerta del Duque de la Victoria), de la derecha (antiguas viviendas de los nâ”œâ•‘meros 14 y 15 de la plaza), como de la parte inferior, que indica que la imagen se capturâ”œâ”‚ en altura. Fuente visual: Jean Laurent y Câ”œآ،a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22091118443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22091118443.webp', 'https://www.flickr.com/photos/zaragozaantigua/22091118443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21080, 'San Miguel c.1877', 'Portada de la iglesia parroquial de San Miguel. Fuente visual: Jean Laurent y Câ”œآ،a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22722769531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22722769531.webp', 'https://www.flickr.com/photos/zaragozaantigua/22722769531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21103, 'Proyecto nuevo parque 1880', '"Primera idea de un parque de Zaragoza", Fâ”œآ®lix Navarro, 15 de diciembre de 1880. Proyecto de parque nuevo en Zaragoza, en la zona de la Huerta de Santa Engracia. Incluye una nueva canalizaciâ”œâ”‚n para el râ”œآ،o Huerva. Fuente: AMZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18936834603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18936834603.webp', 'https://www.flickr.com/photos/zaragozaantigua/18936834603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21127, 'Calle de San Miguel 1880', 'Entorno del Real convento de Religiosas Franciscanas de Santa Catalina trazado en el plano de Dionisio Casaâ”œâ–’al de 1880, segâ”œâ•‘n una copia firmada por el arquitecto municipal Ricardo Magdalena en 1895 con motivo de la nueva alineaciâ”œâ”‚n de la calle de San Miguel y el ensanche en la antigua Huerta de Santa Engracia, que supuso alguna expropiaciâ”œâ”‚n de la antigua huerta del franciscano convento de Santa Catalina, ademâ”œأ­s de la remodelaciâ”œâ”‚n de la fachada principal de ingreso desde la calle de San Miguel, frente a la calle de Santa Catalina, y el levantamiento de un nuevo cerramiento perimetral, segâ”œâ•‘n diseâ”œâ–’o de Ricardo Magdalena. Fuente visual: Real Audiencia de Aragâ”œâ”‚n, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.65035800, -0.87902300, '0101000020E61000005FD1ADD7F420ECBF925852EE3ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40306768155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40306768155.webp', 'https://www.flickr.com/photos/zaragozaantigua/40306768155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21184, 'San Miguel 1890', 'Imagen centrada en la iglesia parroquial de San Miguel de los Navarros y las viviendas a ella adosadas, capturada a cierta altura desde la homâ”œâ”‚nima plaza, de la que emerge vegetaciâ”œâ”‚n arbâ”œâ”‚rea que modelaba su rotonda central. La torre perfila su remate anterior a la intervenciâ”œâ”‚n diseâ”œâ–’ada por Ricardo Magdalena. A la izquierda, detalle del engarce de la iglesia con el cerramiento de la antigua puerta del Duque de la Victoria, cuya sombra se proyecta sobre el exterior del â”œأ­bside mudâ”œآ®jar. Fuente visual: "Iglesia de San Miguel de los Navarros", fototipia de Joarizti y Mariezcurrena, en أ”أ‡آ£Zaragoza Artâ”œآ،stica, Monumental e Histâ”œâ”‚ricaأ”أ‡أک, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64951900, -0.87615100, '0101000020E61000003F726BD26D09ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34224412650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34224412650.webp', 'https://www.flickr.com/photos/zaragozaantigua/34224412650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21218, 'Exposiciâ”œâ”‚n Hispano-Francesa 1908', 'Vista general de los edificios y pabellones de la Exposiciâ”œâ”‚n Hispano-Francesa celebrada en los terrenos de la Huerta de Santa Engracia (hoy plaza de los Sitios) de Zaragoza en 1908, primer centenario de los Sitios. Al fondo, la Escuela de Artes y el Museo. A la derecha, tras el pabellâ”œâ”‚n de maquinaria, los pabellones particulares, entre los cuales sobresale -justo encima de la visual del quiosco de la mâ”œâ•‘sica- el de los Altos Hornos de Vizcaya. Fuente visual: protocolarte.wordpress.com/2014/05/01/inauguracion-de-la-...', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15653181566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15653181566.webp', 'https://www.flickr.com/photos/zaragozaantigua/15653181566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
