INSERT INTO public.photos VALUES (21236, 'Proyecto Huerta Santa Engracia 1906', 'Plano del Proyecto de Urbanizaciâ”œâ”‚n de la Huerta de Santa Engracia de Zaragoza. Subasta de los solares. Litografâ”œآ،a Casas, Zaragoza, 1906. Fuente: AMZ.', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19583414801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19583414801.webp', 'https://www.flickr.com/photos/zaragozaantigua/19583414801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21244, 'Iglesia de San Miguel 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 9, Zaragoza 1908 - Centenario de los Sitios", 1907. "Inmediata a Puerta Quemada por la que entraron los franceses en el primer sitio. El barrio que lleva su nombre llegâ”œâ”‚ a quedar casi desierto y fue preciso trasladar el Santâ”œآ،simo a la Magdalena; pero durante el segundo sitio se colocaron dentro de la iglesia dos caâ”œâ–’ones, con direcciâ”œâ”‚n al puente de San Josâ”œآ®, que defendieron brillantemente aquella puerta de la ciudad." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64903200, -0.87583800, '0101000020E61000007102D369DD06ECBF5B07077B13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20146432054.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20146432054.webp', 'https://www.flickr.com/photos/zaragozaantigua/20146432054/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21259, 'Convento de Santa Catalina 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 26, Zaragoza 1908 - Centenario de los Sitios", 1907. "Uno de los edificios que mâ”œأ­s sufrieron durante el primer sitio. Los franceses lo atacaron violentamente porque a espaldas del convento, en el Jardâ”œآ،n Botâ”œأ­nico, fueron colocadas dos baterâ”œآ،as con las que los zaragozanos les desbarataban todos sus planes." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20583351800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20583351800.webp', 'https://www.flickr.com/photos/zaragozaantigua/20583351800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
