INSERT INTO public.photos VALUES (21319, 'Gran Casino 1908', 'Accidentada imagen capturada durante un baile en el salâ”œâ”‚n del efâ”œآ،mero Gran Casino construido en el recinto de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908, donde la antigua huerta de Santa Engracia. Fuente visual: foto Freudenthal, revista La Actualidad (Barcelona)', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64889400, -0.87941000, '0101000020E6100000C0CFB8702024ECBF0A4966F50ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40557092172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40557092172.webp', 'https://www.flickr.com/photos/zaragozaantigua/40557092172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
