INSERT INTO public.photos VALUES (21759, 'Monumento a los Sitios 1934', 'Monumento a los Sitios en la plaza de Castelar. Al fondo, la calle del Arquitecto Magdalena. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64897500, -0.87940100, '0101000020E6100000F33AE2900D24ECBFF775E09C11D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22618081564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22618081564.webp', 'https://www.flickr.com/photos/zaragozaantigua/22618081564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
