INSERT INTO public.photos VALUES (21841, 'Pl. de Castelar 1938', 'Soleada imagen de un grupo de enfermeras posando durante el II Aâ”œâ–’o Triunfal en la terraza de las Clâ”œآ،nicas de la Cruz Roja chaflaneras entre la plaza de Castelar, que al poco tiempo serâ”œآ،a redenominada en homenaje al ausente Josâ”œآ® Antonio, y la calle de Sancho y Gil. La enfermera de la izquierda es S.A.R. la Serenâ”œآ،sima infanta doâ”œâ–’a Marâ”œآ،a de las Mercedes de Baviera y Borbâ”œâ”‚n, sobrina de Alfonso XIII que, exiliada en Alemania desde la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica Espaâ”œâ–’ola en 1931, habâ”œآ،a regresado tras el 18-19 de julio de 1936 a territorio liberado del comunismo, la juderâ”œآ،a y la masonerâ”œآ،a. Fuente visual: www.memoriademadrid.es/', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.64958100, -0.87861500, '0101000020E610000021CD58349D1DECBF2E8D5F7825D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35173273576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35173273576.webp', 'https://www.flickr.com/photos/zaragozaantigua/35173273576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21942, 'San Miguel aâ”œâ–’os 40', 'Iglesia de San Miguel de los Navarros (Zaragoza), aguafuerte, Jesâ”œâ•‘s Fernâ”œأ­ndez Barrio, Diputaciâ”œâ”‚n de Zaragoza, c. 1945-1947. Fuente: web.dpz.es/arscatalogi.es/', 1940, 1940, 1949, 'Anos 40', 'CENTRO', 41.64918100, -0.87595700, '0101000020E6100000037976F9D607ECBFA017EE5C18D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15689394250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15689394250.webp', 'https://www.flickr.com/photos/zaragozaantigua/15689394250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22008, 'San Miguel c.1941', 'Dibujo representando el alzado de la cabecera de la iglesia parroquial de San Miguel de los Navarros tal y como hubiera quedado de realizarse la intervenciâ”œâ”‚n proyectada por Manuel Lorente en su etapa de Arquitecto-conservador de Monumentos Histâ”œâ”‚rico-Artâ”œآ،sticos de la Tercera Zona (Zaragoza, Huesca, Teruel, Navarra, Guipâ”œâ•‘zcoa, Vizcaya, â”œأ¼lava y Logroâ”œâ–’o). El elemento mâ”œأ­s novedoso de esta reforma hubiera sido, tal vez, la acusada reinterpretaciâ”œâ”‚n de la torre, tras ser despojada de su metâ”œأ­lico y caracteristico chapitel modernista y modelada al gusto estâ”œآ®tico regionalista y nacionalista del Râ”œآ®gimen. Fuente visual: arquitecto Manuel Lorente Junquera, AHPZ.', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.64951900, -0.87615100, '0101000020E61000003F726BD26D09ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40078196625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40078196625.webp', 'https://www.flickr.com/photos/zaragozaantigua/40078196625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22044, 'Calle del Asalto 1951', 'La calle del Asalto, en el tramo comprendido entre la calle del Heroâ”œآ،smo y donde a la derecha y fuera de plano, aâ”œâ–’os mâ”œأ­s tarde serâ”œآ،a prolongada la calle de la Torre, que en esta dâ”œآ®cada todavâ”œآ،a terminaba en la calle de Manuela Sancho. Al fondo se destacan el â”œأ­bside y la torre de la iglesia de San Miguel de los Navarros. A la izquierda, â”œأ­rboles de la ribera del râ”œآ،o Huerva. A la derecha, talleres Vulcan para reparaciâ”œâ”‚n de cubiertas y câ”œأ­maras, que antes estuvieran ubicados en la calle de San Miguel. Este entorno fue utilizado como aparcamiento hasta bien entrados los aâ”œâ–’os 70, como atestiguan los vehâ”œآ،culos estacionados en baterâ”œآ،a. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64921800, -0.87468900, '0101000020E6100000607825C973FDEBBFBDFC4E9319D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14777774729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14777774729.webp', 'https://www.flickr.com/photos/zaragozaantigua/14777774729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22047, 'Iglesia de San Miguel c.1955', 'La iglesia de San Miguel, en una luminosa imagen tomada desde la antigua Ronda o paseo de la Mina. Tras el arbolado, la plaza de San Miguel, y a la derecha, el emboque a la calle de la Reconquista. Muy cerca de donde estuviera la desaparecida puerta del Duque de la Victoria transita un coche motor de la serie 100, posiblemente en servicio en la tranviaria lâ”œآ،nea 1. Bajo Aragâ”œâ”‚n, encaminado hacia el inmediato puente de San Josâ”œآ®. Dos personas aprovechan la agradable solanera, o brasero natural, junto a la tapia del complejo parroquial. Fuente visual: Archivo Coyne, AHPZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64905700, -0.87643300, '0101000020E61000004C530438BD0BECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14863305546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14863305546.webp', 'https://www.flickr.com/photos/zaragozaantigua/14863305546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22151, 'Pl. de San Miguel 1958', 'Tranvâ”œآ،a de "Vâ”œآ،a y obras" en la plaza de San Miguel, vista desde la la calle de Espartero. Al fondo a la derecha, entrada de la calle de la Reconquista. Fuente: "Trenes y tranvâ”œآ،as en el este de Espaâ”œâ–’a", Jeremy Wiseman, Ediciones Treca SL, Gijâ”œâ”‚n 2009, a travâ”œآ®s de www.facebook.com/photo.php?fbid=648195485345119&set=g...', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65005000, -0.87616000, '0101000020E61000000C0742B28009ECBFE561A1D634D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27783752486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27783752486.webp', 'https://www.flickr.com/photos/zaragozaantigua/27783752486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22191, 'Aniversario de los Sitios 1958', 'Cartel diseâ”œâ–’ado por Antonio Margalâ”œآ®, 1958. El 150 aniversario de los Sitios de Zaragoza (1808 y 1809), dio para que el aâ”œâ–’o 1958 estuviese plagado de celebraciones conmemorativas, por parte de las autoridades locales franquistas. Se trataba de rememorar los hechos de la Guerra de la Independencia efectuando un paralelismo con la derrota de la democracia en la Guerra Civil de 1936-1939, dâ”œأ­ndoles a ambas el cariz de cruzada catâ”œâ”‚lica. En el cartel, el monumento a los Sitios de la plaza de Josâ”œآ® Antonio, el laurel como sâ”œآ،mbolo de la victoria, una composiciâ”œâ”‚n con destacadas torres de la ciudad, y la puerta del Carmen. Fuente visual: www.todocoleccion.net', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64898700, -0.87944600, '0101000020E6100000F22213F06B24ECBFBB438A0112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32503259592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32503259592.webp', 'https://www.flickr.com/photos/zaragozaantigua/32503259592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22204, 'Plaza Josâ”œآ® Antonio aâ”œâ–’os 50', 'Vista de la plaza de Josâ”œآ® Antonio nevada, con el Quiosco de la Mâ”œâ•‘sica en primer plano y el monumento a los Sitios a la derecha. Al fondo a la izquierda, la calle de Felipe Sanclemente. Fuente visual: Foto Serrano', 1950, 1950, 1959, 'Anos 50', 'CENTRO', 41.64866600, -0.87948500, '0101000020E610000069520ABABD24ECBF7903CC7C07D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37932736146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37932736146.webp', 'https://www.flickr.com/photos/zaragozaantigua/37932736146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22207, 'Râ”œآ،o Huerva 1951', 'El cauce del râ”œآ،o Huerva con el puente de San Josâ”œآ® al fondo, vistos desde la calle del Asalto. A la izquierda y tras los â”œأ­rboles de la ribera, explanada donde estuvieron los tendederos del lavadero Hondo. Por encima y tras la calle de Miguel Servet, esquinero edificio de la fâ”œأ­brica de pastas para sopa de Pedro Maldonado. A la derecha, justo antes del espacio ocupado por los almacenes de canterâ”œآ،a del Ayuntamiento, restos del pretil en piedra del provisional puente sobre el Huerva de mediados del siglo XIX, ubicado casi a medio camino entre el construido en el siglo XVI, que quedaba mâ”œأ­s hacia la izquierda, ya fuera de plano, y el moderno puente que centra la imagen. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64912400, -0.87455900, '0101000020E6100000D384ED2763FCEBBF3C86C77E16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40559323341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40559323341.webp', 'https://www.flickr.com/photos/zaragozaantigua/40559323341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22370, 'Plaza Josâ”œآ® Antonio 1967', 'Vista aâ”œآ®rea de la plaza de Josâ”œآ® Antonio. En enero de 1968 el quiosco de la mâ”œâ•‘sica serâ”œأ­ desmontado y llevado al parque Primo de Rivera. Fuente: www.facebook.com/photo.php?fbid=10203623723993496&set...', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21649774158.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21649774158.webp', 'https://www.flickr.com/photos/zaragozaantigua/21649774158/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22433, 'Vista aâ”œآ®rea plaza Josâ”œآ® Antonio 1967', 'Vista aâ”œآ®rea desde las inmediaciones de la plaza de Josâ”œآ® Antonio (abajo). Al fondo se distingue el puente del Ferrocarril de la Almozara sobre el Ebro. Fuente: "Zaragoza viva" (1969).', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64892600, -0.87944400, '0101000020E6100000C53A55BE6724ECBF16C3D50110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30034455051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30034455051.webp', 'https://www.flickr.com/photos/zaragozaantigua/30034455051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22706, 'San Miguel 1971', 'Imagen capturada junto a la puerta de ingreso a la iglesia parroquial de San Miguel de los Navarros, durante la salida de un canâ”œâ”‚nico enlace matrimonial realizado segâ”œâ•‘n la liturgia catâ”œâ”‚lica, todo un tratado visual de antropologâ”œآ،a social de la â”œآ®poca. El estallido en rojo del vehâ”œآ،culo desestabiliza el cromatismo preponderante del conjunto, mayormente en tonos azules, y casi le roba el protagonismo a la blanca novia. A la izquierda, aspecto parcial de una de las construcciones adosadas al â”œأ­bside y cuerpo lateral de la iglesia, justo antes de la intervenciâ”œâ”‚n realizada desde la Direcciâ”œâ”‚n General de Bellas Artes del Ministerio de Educaciâ”œâ”‚n, consistente en su derribo, y en la restauraciâ”œâ”‚n de la ornamentaciâ”œâ”‚n exterior original. Este proyecto fue dirigido por el arquitecto Fernando Chueca Goitia. Fuente visual: Patti Larson Photo, en www.flickr.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64970900, -0.87655500, '0101000020E610000022A64412BD0CECBF5C751DAA29D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27823530771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27823530771.webp', 'https://www.flickr.com/photos/zaragozaantigua/27823530771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22789, 'San Miguel 1971', 'Dibujo representando el alzado de la fachada principal de la iglesia parroquial de San Miguel de los Navarros, recayente a la homâ”œâ”‚nima plaza, tal y como hubiera quedado de haberse realizado de forma integral la restauraciâ”œâ”‚n proyectada por el arquitecto Fernando Chueca Goitia. Destaca la reinterpretaciâ”œâ”‚n de la torre mudâ”œآ®jar, posiblemente influida por la reciente intervenciâ”œâ”‚n en la iglesia de la Magdalena y que pretendâ”œآ،a ajustarse a su supuesto estado original. En este caso, el metâ”œأ­lico y caracteristico chapitel modernista figura como remate de un campanario de nueva planta levantado a la derecha de la escultâ”œâ”‚rica portada de ingreso. Fuente visual: Ascensiâ”œâ”‚n Hernâ”œأ­ndez Martâ”œآ،nez, La intervenciâ”œâ”‚n del arquitecto Fernando Chueca Goitia en la iglesia de San Miguel de los Navarros, Zaragoza (1971-1978), IFC, 2013.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64968000, -0.87656900, '0101000020E610000061FF756EDA0CECBFC16ED8B628D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40264335484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40264335484.webp', 'https://www.flickr.com/photos/zaragozaantigua/40264335484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22932, 'Calle de San Miguel 1981', 'Imagen del antiguo edificio nâ”¬â•‘ 38-40 de la calle de San Miguel, chaflanero con la calle de Sancho y Gil (a la derecha), una antigualla provinciana que, en el momento de fotografiarla, ya estaba en trâ”œأ­nsito hacia la nada edilicia. Fuente visual: foto de R. Benedicto, en "Andalâ”œأ­n, periâ”œâ”‚dico quincenal aragonâ”œآ®s".', 1981, 1981, 1981, 'Anos 80', 'CENTRO', 41.65002100, -0.87789600, '0101000020E61000004241295AB917ECBF4B5B5CE333D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31837160053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31837160053.webp', 'https://www.flickr.com/photos/zaragozaantigua/31837160053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23572, 'Calle del Heroâ”œآ،smo 1930', 'Imagen del final de la calle del Heroâ”œآ،smo, aproximadamente en el punto donde estuviera ubicada la desaparecida Puerta Quemada, que daba nombre a esa calle hasta los asedios de 1808-09. A la izquierda, vista parcial del nâ”¬â•‘ 28 de la calle de la Reconquista. Al fondo, esquinero, el nâ”¬â•‘ 1 de la calle de Manuela Sancho, y a la derecha, el nâ”¬â•‘ 53 y el nâ”¬â•‘ 55 de Heroâ”œآ،smo. La captura se ha realizado desde la calle del Asalto, cerca de los almacenes municipales de canterâ”œآ،a inmediatos al puente de San Josâ”œآ®. Un grupo de vecinos, muy interesados en el histâ”œâ”‚rico emplazamiento, posan amablemente ante el objetivo. Fuente visual: Miguel Marâ”œآ،n Chivite, periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64932400, -0.87510700, '0101000020E610000081053065E000ECBF0341800C1DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31698729224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31698729224.webp', 'https://www.flickr.com/photos/zaragozaantigua/31698729224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24115, 'Calle de San Miguel 1959', 'Imagen capturada durante la celebraciâ”œâ”‚n del segundo aniversario de la Cooperativa de Vendedores de Prensa, Revistas y Publicaciones Nacionales, en este caso en la "animada fiesta" que tuvo lugar en los locales de la Cooperativa, sitos en el nâ”¬â•‘ 22 de la calle de San Miguel, como continuaciâ”œâ”‚n menos formal y distendida a la comida de hermandad para un centenar de comensales presidida por el delegado provincial de Sindicatos y procurador en Cortes, Isaâ”œآ،as Monforte Extremiana y otros altos cargos locales del sector del papel, prensa y artes grâ”œأ­ficas, que contâ”œâ”‚ con la asistencia de delegados de otras provincias. A la izquierda de la fila central, Antonio Nasarre de Letosa Sieso, uno de los veteranos fundadores de la Cooperativa, y Antonio Nasarre de Letosa Gimâ”œآ®nez de Bagâ”œâ•‌â”œآ®s, presidente de la misma.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65043600, -0.87927100, '0101000020E61000006747AAEFFC22ECBF0E12A27C41D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52164944009.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52164944009.webp', 'https://www.flickr.com/photos/zaragozaantigua/52164944009/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24133, 'Mosaico Santa Engracia 1907', 'Fotografâ”œآ،a de un mosaico romano del siglo IV, el de fecha mâ”œأ­s reciente hallado en Zaragoza. Decoraba el suelo a dos alturas de un dormitorio, en una finca extramuros de la colonia. Estâ”œأ­ en la Huerta de Santa Engracia, y fue descubierto al remover la zona para instalar la Exposiciâ”œâ”‚n Hispano Francesa de 1908. Archivo fotogrâ”œأ­fico del Museo de Zaragoza.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19156909996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19156909996.webp', 'https://www.flickr.com/photos/zaragozaantigua/19156909996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24136, 'Medalla Exposiciâ”œâ”‚n Hispano Francesa 1908', 'Reverso de la Medalla de Bronce de la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza, 1908. Medalla de 6 cm. acuâ”œâ–’ada por la casa Anduiza de Bilbao. En el anverso figuran los reyes Alfonso XIII y Victoria Eugenia; el reverso muestra una vista panorâ”œأ­mica de la Exposiciâ”œâ”‚n, con el escudo de Zaragoza en la parte inferior y el exergo sin acuâ”œâ–’ar, para grabar el nombre del expositor premiado con ella. Fuente visual: www.museunacional.cat/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19425600470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19425600470.webp', 'https://www.flickr.com/photos/zaragozaantigua/19425600470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24142, 'Inauguraciâ”œâ”‚n Expo 1908', 'La Exposiciâ”œâ”‚n Hispano-Francesa de Zaragoza de 1908, en conmemoraciâ”œâ”‚n del Centenario de los Sitios, fue oficialmente inaugurada el dâ”œآ،a 1â”¬â•‘ de mayo de ese aâ”œâ–’o mediante una ceremonia para la que se habâ”œآ،a levantado un "altar" coronado cerca del Paseo de la Mina. Allâ”œآ،, el infante real D. Carlos estaba en representaciâ”œâ”‚n "especialâ”œآ،sima" de S. M. el Rey Alfonso XIII. Numerosas y altâ”œآ،simas personalidades, representantes de todas las instituciones, el ejâ”œآ®rcito, la Iglesia, y la nobleza de los alrededores, casi no cabâ”œآ،an en el espacio habilitado, separado del vulgo. El turno de los discursos fue inaugurado por el Arzobispo (el inefable Juan Soldevila y Romero), al que siguieron Basilio Paraâ”œآ،so (por el Comitâ”œآ® de Organizaciâ”œâ”‚n del Certamen), el Alcalde (Antonio Fleta) y el Ministro de Fomento (Augusto Gonzâ”œأ­lez Besada), antes de culminar con el del Infante, que tras concluir la lectura del mismo declarâ”œâ”‚ abierta la Exposiciâ”œâ”‚n, en nombre del Rey. Para escenificar mâ”œأ­s teatralmente la buena nueva, el secretario de la sociedad Colombâ”œâ”‚fila de Barcelona soltâ”œâ”‚ mâ”œأ­s de 300 palomas que tomaron el camino hacia la ciudad condal para confirmar con su vuelo que la Exposiciâ”œâ”‚n estaba inaugurada. En la Imagen se ha capturado un instante de la intervenciâ”œâ”‚n del Infante D. Carlos (acompaâ”œâ–’ado, a nuestra derecha, por el infante Don Luis Alfonso de Orleâ”œأ­ns, con sombrero de copa, aunque descubierto) en el ceremonial "Altar" instalado en la esquina del edificio de "La Caridad", que como parte integrante de los temporales pabellones de la Expo, fue "Palacio de Industrias". Actualmente en esta esquina confluyen la plaza de los Sitios y la calle Moret. Fuente visual: Foto Escolâ”œأ­, para la revista "Mercurio".', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64865700, -0.87858400, '0101000020E6100000603E59315C1DECBF26A94C3107D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20212694702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20212694702.webp', 'https://www.flickr.com/photos/zaragozaantigua/20212694702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24144, 'Edificio de las Escuelas 1907', 'Foto: Escolâ”œأ­. Construcciâ”œâ”‚n del edificio de las Escuelas de la Exposiciâ”œâ”‚n Hispano Francesa de 1908, proyectado por el arquitecto Fâ”œآ®lix Navarro. Al fondo a la izquierda emerge el remate de la torre de la iglesia parroquial de San Miguel de los Navarros.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64894500, -0.87853000, '0101000020E610000094C151F2EA1CECBF8CF337A110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21019568776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21019568776.webp', 'https://www.flickr.com/photos/zaragozaantigua/21019568776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24150, 'Proyecto Exposiciâ”œâ”‚n Hispano-Francesa 1907', '"Proyecto de la Exposiciâ”œâ”‚n Hispano-Francesa que debe celebrarse en Zaragoza de mayo a octubre de 1908. Vista general segâ”œâ•‘n el proyecto. Edificios principales en construcciâ”œâ”‚n". Ilustraciâ”œâ”‚n que refleja el recinto de la muestra, en la Huerta de Santa Engracia, con detalle numerado de sus hitos, el râ”œآ،o Huerva rodeâ”œأ­ndolo a la derecha y las casas de la calle de San Miguel arriba a la izquierda. Fuente: Diario ABC, 5 de diciembre de 1907.', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64893400, -0.87938900, '0101000020E6100000E2C96E66F423ECBF98A1F14410D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25835661307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25835661307.webp', 'https://www.flickr.com/photos/zaragozaantigua/25835661307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24153, 'Huerta de Santa Engracia 1907', 'Imagen capturada en los terrenos de la antigua huerta de Santa Engracia durante las obras de construcciâ”œâ”‚n de los pabellones y edificios proyectados en el interior del recinto de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. La fotografâ”œآ،a se habrâ”œآ،a realizado desde las traseras del edificio proyectado como "Escuelas". Al fondo, la iglesia parroquial de Santa Engracia. A la izquierda, arboleda ribereâ”œâ–’a del râ”œآ،o Huerva junto al paseo de la Mina. Fuente visual: "Libro de Oro. Exposiciâ”œâ”‚n Hispano-Francesa de 1908".', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64894500, -0.87853000, '0101000020E610000094C151F2EA1CECBF8CF337A110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30102769487.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30102769487.webp', 'https://www.flickr.com/photos/zaragozaantigua/30102769487/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24157, 'Inauguraciâ”œâ”‚n Exposiciâ”œâ”‚n 1908', 'El arzobispo Juan Soldevila Romero oficia en un altar de campaâ”œâ–’a la inauguraciâ”œâ”‚n de la Exposiciâ”œâ”‚n Hispano-Francesa, el 1 de mayo de ese aâ”œâ–’o, junto al edificio de Artes e Industrias. Al fondo, el Jardâ”œآ،n Botâ”œأ­nico. Fuente visual: La Ilustraciâ”œâ”‚n Artâ”œآ،stica (BCN)', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64867700, -0.87861800, '0101000020E610000065A9F57EA31DECBF6D5512D907D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32431400223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32431400223.webp', 'https://www.flickr.com/photos/zaragozaantigua/32431400223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24158, 'Templete 1908', 'Foto: Aurelio Grasa. Templete en la futura calle de Moret, desde el que se inaugurâ”œâ”‚ la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. A la izquierda, el Edificio de Artes e Industrias, y a la derecha, el Edificio Museos. Fuente: Archivo Barboza-Grasa, a travâ”œآ®s de Heraldo de Aragâ”œâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64871800, -0.87870400, '0101000020E610000009A9DBD9571EECBFCC29013109D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32686609792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32686609792.webp', 'https://www.flickr.com/photos/zaragozaantigua/32686609792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24160, 'Huerta de Santa Engracia c.1907', 'Despejada imagen panorâ”œأ­mica de la antigua huerta de Santa Engracia, capturada a ras de suelo durante las obras de nivelaciâ”œâ”‚n del terreno para el inicio de las obras de construcciâ”œâ”‚n del recinto de la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. Fue en este lugar donde volviâ”œâ”‚ a ver la luz un mosaico tardorromano datado en el siglo IV, posiblemente de una villa de la periferia agrâ”œآ،cola de la ciudad. A la izquierda, la iglesia de Santa Engracia y, adosado, los restos del cuartel homâ”œâ”‚nimo. A la derecha, la câ”œâ•‘pula de la antigua iglesia de San Ildefonso, convertida recientemente en parroquia de Santiago el Mayor. Entre ambas iglesias, las traseras orientales de la calle de la Independencia. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1907, 1907, 1907, 'Anos 1900', 'CENTRO', 41.64898700, -0.87944600, '0101000020E6100000F22213F06B24ECBFBB438A0112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33340525010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33340525010.webp', 'https://www.flickr.com/photos/zaragozaantigua/33340525010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24272, 'Plaza de Castelar 1930', '"Escuela de Industria y bellas Artes", en la Plaza de Castelar.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64894500, -0.87853000, '0101000020E610000094C151F2EA1CECBF8CF337A110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866205694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866205694.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866205694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24277, 'Alfonso XIII 1908', '28 de octubre de 1908. El rey Alfonso XIII preside, junto a su esposa Victoria Eugenia, la inauguraciâ”œâ”‚n del monumento a Los Sitios, situado hoy en el centro de la plaza del mismo nombre.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64890300, -0.87926500, '0101000020E6100000DE8E705AF022ECBF5DA3E5400FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14966488561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14966488561.webp', 'https://www.flickr.com/photos/zaragozaantigua/14966488561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24279, '&quot;Edificio de Artes e Industrias&quot; 1908', 'AHPZ. Archivo Coyne. Ignacio Coyne. 1908. La Escuela de Artes y Oficios de Zaragoza se habâ”œآ،a inaugurado en 1895, en la antigua Facultad de Medicina y Ciencias. En 1908 se trasladâ”œâ”‚ a la plaza de Castelar, a un edificio que habâ”œآ،a formado parte de la Exposiciâ”œâ”‚n Hispano-Francesa, denominado "Edificio de Artes e Industrias", y que tras la muestra fue redenominado como "Escuelas de Industrias y Bellas Artes, de Comercio y de Artes y Oficios". La imagen parece clara en varios aspectos, todos ellos desaparecidos luego: contaba desde el principio con su propia valla de forja; pinturas alusivas a las artes y oficios decoraban secciones de los muros de la fachada principal; una galerâ”œآ،a de pequeâ”œâ–’as reproducciones de la Tour Eiffel aireaban la estructura.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64894500, -0.87853000, '0101000020E610000094C151F2EA1CECBF8CF337A110D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15021312272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15021312272.webp', 'https://www.flickr.com/photos/zaragozaantigua/15021312272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24282, 'Josephine Baker 1930', 'A mediados del mes de marzo de 1930, mientras el Ebro se salâ”œآ،a de madre de forma tremenda, la Sociedad Anâ”œâ”‚nima General de Espectâ”œأ­culos propiciâ”œâ”‚ la actuaciâ”œâ”‚n en el Teatro-Cine Parisiana de Zaragoza de la "Venus de â”œآ®bano", la "Artista mundial", la "Danzarina de los ritmos exâ”œâ”‚ticos" la afronorteamericana de 23 aâ”œâ–’os de edad Freda Josephine Baker Carson, de nombre artâ”œآ،stico Josephine Baker. Completaban el espectâ”œأ­culo nâ”œâ•‘meros de Moritz, "Bailarâ”œآ،n excâ”œآ®ntrico americano"; Conchita de Leonardo, "Notabilâ”œآ،sima cancionista"; Pompoff-Thedy, "Famosos clowns musicales"; Lina Jack et Farbell, "Câ”œآ®lebre pareja de bailes acrobâ”œأ­ticos"; Custodia Romero, "La Venus de bronce"; y "La formidable orquesta" Manhatam (sic) Players. A las previstas funciones dobles (18:15 y 22.15 h.) de los dâ”œآ،as 14 y 15 se le aâ”œâ–’adiâ”œâ”‚ de forma excepcional una tercera jornada el dâ”œآ،a 16, domingo, cuya â”œâ•‘ltima funciâ”œâ”‚n incluyâ”œâ”‚ una "Serenata d''onore a la Venus de â”œآ®bano", un "Cuadro de Jota" integrado por Lazarito y Maruja Esteso, Marâ”œآ،a Asensio, Juan Antonio Gracia y Josâ”œآ® Esteso, y una lectura de cuartillas titulado "Homenaje de Zaragoza a Josefina Baker". En la imagen, posado de Josephine Baker a los pies del Monumento a los Sitios en la plaza de Castelar. En 1936 adquiriâ”œâ”‚ la ciudadanâ”œآ،a francesa, y durante la Segunda Guerra Mundial ejerciâ”œâ”‚ de agente del espionaje francâ”œآ®s ("le Deuxiâ”œآ؟me Bureau"), filtrando informaciâ”œâ”‚n a los Aliados de movimientos de tropas del Eje, y pudo hacerse con un libro de câ”œâ”‚digos y claves italo-alemanas. En febrero de 1973, con 66 aâ”œâ–’os de edad, Josephine Baker regresâ”œâ”‚ a Zaragoza para actuar en la sala "Cancela". Falleciâ”œâ”‚ dos aâ”œâ–’os mâ”œأ­s tarde. Fuente visual: foto Marâ”œآ،n Chivite, en "Instantâ”œأ­neas zaragozanas", CAZAR, 1982.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64883900, -0.87928700, '0101000020E6100000D388997D1E23ECBF47AF06280DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15158126822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15158126822.webp', 'https://www.flickr.com/photos/zaragozaantigua/15158126822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24284, 'Santa Catalina 1808', '"Vista del costado de la iglesia de las monjas de Santa Catalina". Serie Ruinas de Zaragoza, de Juan Gâ”œأ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œأ­diz, 1812. La iglesia del monasterio de monjas clarisas o dueâ”œâ–’as menoretas de Santa Catalina, el cenobio femenino mâ”œأ­s antiguo de Zaragoza, resultâ”œâ”‚ bastante daâ”œâ–’ada en los Sitios. Ademâ”œأ­s, a principios del siglo XX se derribâ”œâ”‚ por motivos urbanâ”œآ،sticos lo que todavâ”œآ،a se mantenâ”œآ،a en pie, cayendo la interesante Sala Capitular. Reconstruidos convento e iglesia, permanecen en la esquina de las calles Arquitecto Magdalena y San Miguel. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15265014931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15265014931.webp', 'https://www.flickr.com/photos/zaragozaantigua/15265014931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25635, 'Av. de Juan Carlos I 2005', 'Imagen capturada desde la altura del nâ”¬â•‘ 25 de la avenida de Gâ”œâ”‚mez Laguna durante la gran nevada de finales de febrero de 2005, con buena visual del solar comprendido entre las avenidas de Juan Carlos I (izquierda) y Juan Pablo II (derecha). Al fondo, tras la avenida de Ramâ”œâ”‚n Sainz de Varanda, el Centro de Formaciâ”œâ”‚n Juan Pablo II de una conocida entidad de ahorro local hoy desaparecida. En este solar serâ”œآ،a construido mâ”œأ­s tarde el gran complejo del Centro comercial Aragonia, inaugurado en 2009. Fuente visual: foto Sergi en www.flickr.com/photos/sergutel/2279394715/in/album-721576...', 2005, 2005, 2005, 'Siglo XXI', 'UNIVERSIDAD', 41.64018700, -0.90920600, '0101000020E610000096766A2E3718EDBF8429CAA5F1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42730837162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42730837162.webp', 'https://www.flickr.com/photos/zaragozaantigua/42730837162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24285, 'Huerta de Santa Engracia 1928', 'Julio Yanguas. 1928. "Huerta de Santa Engracia". El "Hospital Victoria Eugenia de la Cruz Roja Espaâ”œâ–’ola" fue proyectado en 1924 por Miguel â”œأ¼ngel Navarro Pâ”œآ®rez, e inaugurado en enero de 1928. Es un notable ejemplo del eclecticismo de los aâ”œâ–’os 20 y 30 del pasado siglo, que conjunta muy bien con el paisaje urbano definido por los edificios supervivientes de la Expo 1908, y el inmediato Grupo Escolar "Gascâ”œâ”‚n y Marâ”œآ،n". La imagen estâ”œأ­ tomada desde un vial sin nombre que un par de aâ”œâ–’os despuâ”œآ®s recibirâ”œأ­ el nombre de "Sancho y Gil". A la derecha queda el edificio de la Cruz Roja, reciâ”œآ®n estrenado. Al fondo, la foresta que estaba empezando a caracterizar la Plaza de Castelar, que fuera parte del recinto de la Expo de 1908. Fuente visual: "Luces de la ciudad. Arte y Cultura en Zaragoza. 1914-1936", aâ”œâ–’o 1995.', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64961900, -0.87832600, '0101000020E6100000753FA7203F1BECBF1CEE23B726D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15313282210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15313282210.webp', 'https://www.flickr.com/photos/zaragozaantigua/15313282210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24293, 'Anfiteatro siglo I', 'Mapa de situaciâ”œâ”‚n del anfiteatro romano de Zaragoza, construido en el siglo I de nuestra era, segâ”œâ•‘n propuesta de ubicaciâ”œâ”‚n de Pilar Diarte Blasco et al. ("Una nueva hipâ”œâ”‚tesis sobre la localizaciâ”œâ”‚n del anfiteatro de Caesaraugusta", Pyrenae, Revista de Prehistoria y Antigâ”œâ•‌edad del Mediterrâ”œأ­neo Occidental, nâ”œâ•‘m 44, 2013). Una hipâ”œâ”‚tesis anterior apunta a otro posible lugar: www.flickr.com/photos/126653716@N03/15725380705. La ubicaciâ”œâ”‚n en la huerta de Santa Engracia es desmentida en el estudio "Nuevas cuestiones sobre el anfiteatro de Zaragoza" (2016), de Josâ”œآ® David Mendoza: www.um.es/cepoat/pantarei/wp-content/uploads/2016/10/pant.... Fuentes de los datos: www.academia.edu/3687122/Una_nueva_hip%C3%B3tesis_sobre_l... prensa.unizar.es/noticias/1306/130613_z0_anfiteatro.pdf Fuente del plano:', 50, NULL, 99, 'Siglo XIX', 'CENTRO', 41.64905700, -0.87911200, '0101000020E610000047AD307DAF21ECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15906334241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15906334241.webp', 'https://www.flickr.com/photos/zaragozaantigua/15906334241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24296, 'Santa Catalina c.1930', 'Foto Albareda, puerta de acceso a la Sala Capitular del monasterio de Santa Catalina. Ca. 1930. En la tercera dâ”œآ®cada del s. XIII fue fundado el monasterio de monjas de la Orden de San Damiâ”œأ­n, bajo la advocaciâ”œâ”‚n de Santa Catalina, por la existencia previa, en el lugar de su construcciâ”œâ”‚n, de una ermita dedicada a esta santa, cerca del Monasterio de Santa Engracia. La original fâ”œأ­brica del monasterio de Santa Catalina se realizâ”œâ”‚ en la primera mitad del s. XIV en formas mudâ”œآ®jares (con las habituales reformas barrocas en el XVII), de las que sâ”œâ”‚lo restan algunas partes de la actual iglesia, tras la desapariciâ”œâ”‚n de todas las antiguas dependencias, primero por los efectos de los duros combates de 1808-1809, y despuâ”œآ®s, en la tercera dâ”œآ®cada del s. XX, con las obras de reforma y ampliaciâ”œâ”‚n. Bajo esta â”œâ•‘ltima intervenciâ”œâ”‚n fue piqueteada la superviviente Sala Capitular, cuya puerta de acceso representa la imagen superior, antes del acto. Sic transit gloriae mundi. Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16360910582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16360910582.webp', 'https://www.flickr.com/photos/zaragozaantigua/16360910582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24298, 'Pabellâ”œâ”‚n de Fomento 1908', 'Foto: Ignacio Coyne, 1908. Pabellâ”œâ”‚n del Ministerio de Fomento en la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza. Detrâ”œأ­s del fotâ”œâ”‚grafo, la Escuela de Artes. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64911200, -0.87886400, '0101000020E61000003F373465A71FECBF78B81D1A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18989527873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18989527873.webp', 'https://www.flickr.com/photos/zaragozaantigua/18989527873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24305, 'Pabellâ”œâ”‚n de Fomento 1908', 'Imagen de la monumental puerta de acceso al Pabellâ”œâ”‚n del Ministerio de Fomento de la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza, obra del arquitecto Carlos Gato y Soldevilla. En planta rectangular de una altura, se alargaba hasta los 72 metros, y estaba ricamente decorado, imitando acabados propios de la piedra caliza, en un estilo muy al gusto del Modernismo "Sezession". En su interior, tres secciones mostraban los â”œâ•‘ltimos adelantos en lo referido a Agricultura, a Caminos, Minas y Montes, y al Canal de Aragâ”œâ”‚n y Cataluâ”œâ–’a. La presencia en la imagen de varias personas permite captar en su verdadera dimensiâ”œâ”‚n las proporciones y medidas de este Pabellâ”œâ”‚n, pues sin ellas, parecerâ”œآ،an colosales. Fuente visual: Revista Arquitectura y Construcciâ”œâ”‚n, 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64911200, -0.87886400, '0101000020E61000003F373465A71FECBF78B81D1A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19583826063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19583826063.webp', 'https://www.flickr.com/photos/zaragozaantigua/19583826063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24308, 'Huerta de Santa Engracia 1863', 'Plano de la Huerta de Santa Engracia de Zaragoza y alrededores en 1863. Fuente: â”¬أ­Aquâ”œآ،... Zaragoza!, Josâ”œآ® Blasco Ijazo, 1953.', 1863, 1863, 1863, 'Siglo XIX', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19692704800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19692704800.webp', 'https://www.flickr.com/photos/zaragozaantigua/19692704800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24310, 'Espacio Goya 2006', 'Recreaciâ”œâ”‚n virtual del proyecto de Herzog y De Meuron para crear un Espacio Goya en los edificios de la Escuela de Artes y el Museo de Zaragoza, en 2006. La prouesta, que debâ”œآ،a estar lista para los fastos de 2008, no prosperâ”œâ”‚. No obstante, se construyâ”œâ”‚ una nueva Escuela de Artes en la Margen Izquierda y se abandonâ”œâ”‚ la que nos ocupa. En 2015, Ibercaja, banco propietario del Museo Camâ”œâ”‚n Aznar, lo redenominâ”œâ”‚ "Museo Goya colecciâ”œâ”‚n Ibercaja", con la esperanza de ampliar su espacio aâ”œâ–’adiâ”œآ®ndole un solar municipal de la calle Santiago. Fuente visual: archidose.blogspot.com.es/2009/04/espacio-goya.html', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.64873600, -0.87869200, '0101000020E6100000F83768AF3E1EECBF72DEFFC709D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19924207315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19924207315.webp', 'https://www.flickr.com/photos/zaragozaantigua/19924207315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24313, 'Vista aâ”œآ®rea plaza de los Sitios 1986', 'Foto: Josâ”œآ® Luis Pomarâ”œâ”‚n Vista aâ”œآ®rea del entorno de la plaza de los Sitios de Zaragoza. Al fondo, junto a los bloques de la calle Coâ”œآ،mbra, el gasâ”œâ”‚metro desmantelado. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.64897500, -0.87940100, '0101000020E6100000F33AE2900D24ECBFF775E09C11D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22130364629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22130364629.webp', 'https://www.flickr.com/photos/zaragozaantigua/22130364629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24317, 'Calle de Sancho y Gil 1928', 'Imagen de la nueva sede de la Mutua de Accidentes de Zaragoza, ubicada en la calle Sancho y Gil nâ”œâ•‘mero 4, en una parte del antiguo Jardâ”œآ،n Botâ”œأ­nico de Zaragoza, reurbanizado tras la Exposiciâ”œâ”‚n Hispano Francesa de 1908. El edificio fue diseâ”œâ–’ado por Marcelino Securun Orga, como una recreaciâ”œâ”‚n de las formas de los antiguos edificios seâ”œâ–’oriales de la ciudad de los siglos XV-XVI, en ladrillo. A su izquierda, la antigua Capilla de Jesâ”œâ•‘s Reparador, de las Religiosas Reparadoras del Sagrado Corazâ”œâ”‚n, que serâ”œآ،a reconstruida de nueva planta en los aâ”œâ–’os 60. Fuente visual: www.maz.es/', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64990100, -0.87830400, '0101000020E610000080457EFD101BECBFA051BAF42FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30647425396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30647425396.webp', 'https://www.flickr.com/photos/zaragozaantigua/30647425396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24320, 'Huerta de Santa Engracia 1908', 'Imagen del efâ”œآ،mero pabellâ”œâ”‚n del Ministerio de Fomento levantado en la Exposiciâ”œâ”‚n Hispano Francesa de 1908, en la antigua huerta de Santa Engracia. A la izquierda, un molino de viento extractor de agua con publicidad de la local "Fundiciâ”œâ”‚n Pellicer y Juan", y detrâ”œأ­s, muro perimetral de la huerta del convento de Santa Catalina. Detrâ”œأ­s del pabellâ”œâ”‚n, altos â”œأ­rboles del Jardâ”œآ،n Botâ”œأ­nico. Al fondo, a la derecha, sobresale el perdurable "Edificio de Artes e Industrias", luego "Escuelas de Industrias y Bellas Artes, de Comercio y de Artes y Oficios", con sus caracterâ”œآ،sticas y efâ”œآ،meras reproducciones de la Tour Eiffel. El Monumento a los Sitios estaba justo donde termina la imagen, a la derecha, casi frente a la puerta principal de ingreso al pabellâ”œâ”‚n de Fomento. Esta imagen, capturada por Ignacio Coynâ”œآ® ("Coyne Foto"), formaba parte de una serie de postales dedicada a la Expo 1908. Fuente visual: www.ebay.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64914000, -0.87914100, '0101000020E6100000DA53724EEC21ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31362743796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31362743796.webp', 'https://www.flickr.com/photos/zaragozaantigua/31362743796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24322, 'Calle Moret 2008', 'Foto: Josâ”œآ® Miguel Marco. Vista desde la plaza de Los Sitios de la calle de Segismundo Moret. Este vial fue propuesto para albergar en su subsuelo un aparcamiento, en 1989, 1994 y 2008. En marzo de 2016 comenzaron, esta vez sâ”œآ،, las obras, para su inauguraciâ”œâ”‚n en 2017. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.64865700, -0.87858400, '0101000020E6100000603E59315C1DECBF26A94C3107D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31863403134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31863403134.webp', 'https://www.flickr.com/photos/zaragozaantigua/31863403134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24330, 'Arquitecto Magdalena 1929', 'Imagen capturada durante las obras de ampliaciâ”œâ”‚n y reforma del franciscano convento de Santa Catalina. En este caso, se trata del nuevo pabellâ”œâ”‚n de tres plantas de altura proyectado por Luis de La Figuera en estilo historicista y neogâ”œâ”‚tico, con fachada a la nueva calle del Arquitecto Magdalena. Al fondo, a la derecha, el muro de la despejada zona conventual que hacâ”œآ،a esquina a la plaza de Castelar. Hacia la izquierda, la calle de San Miguel. Este fue el convento mâ”œأ­s antiguo de la ciudad, fundado en el primer tercio del siglo XIII, si bien la construcciâ”œâ”‚n del mismo data del siglo siguiente, en gâ”œâ”‚tico mudâ”œآ®jar, con reformas posteriores. Su extensiâ”œâ”‚n, entonces, era mucho mâ”œأ­s destacada, incluyendo gran claustro y amplia zona de huerta delimitada por la muralla de rejola. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65003800, -0.87911900, '0101000020E6100000E659492BBE21ECBF2194F77134D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36565173482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36565173482.webp', 'https://www.flickr.com/photos/zaragozaantigua/36565173482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24331, 'Arquitecto Magdalena 1929', 'Imagen capturada durante las obras de ampliaciâ”œâ”‚n y reforma del franciscano convento de Santa Catalina (a la derecha) como consecuencia de la reurbanizaciâ”œâ”‚n de la zona, que incluyâ”œâ”‚ la apertura de un nuevo vial que prolongaba la calle de Santa Catalina, y que recibirâ”œآ،a el nombre de Arquitecto Magdalena. A la izquierda, irregular traza con algunos restos edilicios previos a la apertura del nuevo vial, luego derribados y sobre cuyos solares se levantarâ”œأ­n el nâ”¬â•‘ 22 de la calle de San Miguel. el nâ”¬â•‘ 4 de Arquitecto Magdalena y el nâ”¬â•‘ 14 de la plaza de Castelar. Al fondo, la estrecha calle de Santa Catalina, a cuya izquierda queda el antiguo nâ”¬â•‘ 16 de esa calle, que serâ”œآ،a derribado dâ”œآ®cadas despuâ”œآ®s para acometer una nueva ampliaciâ”œâ”‚n del colegio de las Hijas de la Caridad de Santa Ana. A la derecha, el nâ”¬â•‘ 17 de la calle de San Miguel. El proyecto de apertura de este nuevo vial incluâ”œآ،a â”œأ­rboles a ambos lados de la calle, para dar mâ”œأ­s lustre (y sombra) a una codiciada zona que era considerada &quot;aristocrâ”œأ­tica&quot;. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65003800, -0.87911900, '0101000020E6100000E659492BBE21ECBF2194F77134D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36597010771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36597010771.webp', 'https://www.flickr.com/photos/zaragozaantigua/36597010771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24337, 'Plaza de Castelar 1929', 'Imagen capturada desde la plaza de Emilio Castelar y centrada en el reciente inmueble del nâ”¬â•‘ 12 de la calle del Arquitecto Magdalena (actual nâ”¬â•‘ 18 de la plaza de los Sitios), en el centro de la despejada manzana delimitada entre las calles de Felipe Sanclemente, hacia la izquierda, y la de Jerâ”œâ”‚nimo Zurita, hacia la derecha. Este edificio, proyectado por Fernando Garcâ”œآ،a Mercadal, es considerado el primero del racionalismo arquitectâ”œâ”‚nico construido en la ciudad. En 1956 se le aâ”œâ–’adirâ”œأ­ una planta extra, que le darâ”œآ،a su altura actual.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.64946600, -0.87970000, '0101000020E61000008351499D8026ECBF95EEAEB321D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49948509017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49948509017.webp', 'https://www.flickr.com/photos/zaragozaantigua/49948509017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24339, 'Plaza de los Sitios 1990', 'El CAI Zaragoza, equipo de baloncesto de la ciudad, asâ”œآ، denominado entre 1982 y 1992, ganâ”œâ”‚ la Copa del Rey en dos ocasiones. En 1984 contra el FC Barcelona, y en 1990 contra el Joventut de Badalona. En la foto, posado del conjunto en el monumento a los Sitios de la plaza homâ”œâ”‚nima, celebrando la â”œâ•‘ltima victoria mencionada. De pie y de izquierda a derecha: Fernando Arcega, Joaquâ”œآ،n Ruiz Lorente, Francisco Murcia, Josâ”œآ® Luis Oliete y Jesâ”œâ•‘s "Chuchi" Carrera (tâ”œآ®cnicos), Mark Davis, Josâ”œآ® Miguel Hernâ”œأ­ndez, Aleksander Belostenny. Sentados y de izquierda a derecha: Luis Melendo (delegado del equipo), Francisco "Paco" Binaburo (fisioterapeuta), Josâ”œآ® â”œأ¼ngel "Pepe" Arcega, Santiago Aldama, Francisco "Paco" Zapata, Quique Andreu, Alberto Angulo, Daniel â”œأ¼lvarez, Josâ”œآ® "Pepe" Costa (preparador fâ”œآ،sico) y Fâ”œآ®lix Gâ”œâ”‚mez (doctor).', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.64890400, -0.87938900, '0101000020E6100000E2C96E66F423ECBF2E1F49490FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50213919188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50213919188.webp', 'https://www.flickr.com/photos/zaragozaantigua/50213919188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24340, 'Plaza de los Sitios 1998', 'Imagen capturada durante las obras de urbanizaciâ”œâ”‚n y embellecimiento de la plaza de los Sitios que al homâ”œâ”‚nimo monumento le dotaron de la fuente que desde entonces lo rodea, y que fueron acometidas durante la etapa de Luisa Fernanda Rudi como alcaldesa. Al fondo y sobre los â”œأ­rboles de la plaza emergen los edificios del Museo Provincial y Escuela de Bellas Artes.', 1998, 1998, 1998, 'Anos 90', 'CENTRO', 41.64890400, -0.87938900, '0101000020E6100000E2C96E66F423ECBF2E1F49490FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50512143803.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50512143803.webp', 'https://www.flickr.com/photos/zaragozaantigua/50512143803/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24342, 'Plaza de Josâ”œآ® Antonio 1978', '"Plaza de Josâ”œآ® Antonio". â”œأ´leo sobre lienzo, 73 x 54 cm, Carmen Faci, 1978. Preside el cuadro el Monumento a los Sitios.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64896400, -0.87944800, '0101000020E6100000200BD1217024ECBF03249A4011D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53637579633.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53637579633.webp', 'https://www.flickr.com/photos/zaragozaantigua/53637579633/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24497, 'Calle de San Miguel c.1973', 'El antiguo nâ”¬â•‘ 45 de la calle de San Miguel, esquinero con la de Comandante Repollâ”œآ®s, y vecino del pâ”œآ®treo y caracterâ”œآ،stico nâ”¬â•‘ 43, fue derribado a mediados de los aâ”œâ–’os 60, y sobre su solar se construyâ”œâ”‚ un nuevo bloque de viviendas con notable desarrollo vertical. En su planta calle abriâ”œâ”‚ al pâ”œâ•‘blico un establecimiento comercial denominado "Supermercado del Hogar", que ahora cumple su aniversario 50. En la imagen, achaflanado y nutrido escaparate de esta tienda a lo "13 Rue del Percebe", una de sus originales seâ”œâ–’as de identidad, como gran expositor del aparataje domâ”œآ®stico asociado a una vida moderna y elâ”œآ®ctrica a 220v. En el cartel anunciador, que perdura, referencia a las clâ”œأ­sicas marcas comerciales "De Wald" (auto-radio y TV), e "Invicta" (radio y TV). Fuente visual: amable aportaciâ”œâ”‚n personal de Jesus Pablo Corvinos.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64981000, -0.87698600, '0101000020E61000006C98A1F14410ECBF904E5DF92CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30209167972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30209167972.webp', 'https://www.flickr.com/photos/zaragozaantigua/30209167972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24897, 'Calle de San Miguel 1958', 'Dâ”œآ،a lluvioso en la calle de San Miguel, desde cierta altura en los aledaâ”œâ–’os de la plaza homâ”œâ”‚nima, con detalle de los reflejos de la luz sobre el mojado adoquinado y las zonas parcheadas con asfalto. A la derecha, la casa con revestimiento en piedra y puerta con forma de arco del nâ”¬â•‘ 43, cuyo singular aspecto fue acicate para el popular ejercicio de invenciâ”œâ”‚n de leyendas urbanas como la del duende o personaje aquâ”œآ، encerrado que nunca se cortâ”œâ”‚ las uâ”œâ–’as. Varias personas transitan el vial, junto a la esquina de la calle de Miguel Alluâ”œآ® Salvador, donde estaba la academia de conductores Aragâ”œâ”‚n. Fuente visual: Foto Josâ”œآ® Antonio Duce', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64980500, -0.87707500, '0101000020E610000054742497FF10ECBF7EE36BCF2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15223546026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15223546026.webp', 'https://www.flickr.com/photos/zaragozaantigua/15223546026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24976, 'Leoncio, del Botâ”œأ­nico 1913', 'Una de las iniciativas de la ilustrada "Real Sociedad Econâ”œâ”‚mica de Amigos del Paâ”œآ،s" de Zaragoza, fue establecer un "Jardâ”œآ،n experimental" como plantero de especies vegetales exâ”œâ”‚ticas y nativas, y como aulario para enseâ”œâ–’anza de la ciencia botâ”œأ­nica y su relaciâ”œâ”‚n con la medicina. Asâ”œآ،, arrendâ”œâ”‚ unos terrenos cerca de la plaza de San Miguel, medianera con las monjas de Santa Catalina, enfrente a las calles de Urreas y Rufas, y allâ”œآ، se construyeron aulas para alumnos, y el suelo fue dispuesto para cultivos, con su riego. Fue inaugurado en 1778. Los sucesos bâ”œآ®licos de 1808-09 lo dejaron arruinado, y los intentos por recuperarlo sâ”œâ”‚lo cuajaron en 1843, cuando se traspasâ”œâ”‚ su gestiâ”œâ”‚n a la Universidad, ya como "Jardâ”œآ،n Botâ”œأ­nico", en la misma ubicaciâ”œâ”‚n. En 1860 se extendâ”œآ،a por 3800 m2, con unas 1500 especies de plantas en nâ”œâ”‚mina, riego suficiente, y buena visual de las afueras de la ciudad. Se entraba por la calle de San Miguel nâ”¬â•‘ 30, y era visitable. Leoncio Gâ”œâ”‚mez Gimeno, perito agrâ”œâ”‚nomo, fue el primer jardinero de esta segunda y larga â”œآ®poca del botâ”œأ­nico, en el que estuvo trabajando hasta su retiro, muchas dâ”œآ®cadas despuâ”œآ®s. Esta imagen de Leoncio sentado, tomada junto a los invernaderos, formaba parte de un reportaje dedicado a su larga trayectoria como "Patriarca del Botâ”œأ­nico", y fue publicado en el local periâ”œâ”‚dico "La Crâ”œâ”‚nica" el 18 de abril de 1913. La progresiva urbanizaciâ”œâ”‚n del entorno de la antigua Huerta de Santa Engracia, tras la Expo de 1908, provocâ”œâ”‚ el "traslado" del Botâ”œأ­nico, en 1923, a unos amplios espacios en el paseo de Ruiseâ”œâ–’ores, donde se estaba levantando la Residencia de Estudiantes de la Universidad, que fue su vecina hasta 1936. En este traslado se consolida el cambio de orientaciâ”œâ”‚n del Botâ”œأ­nico, ya como un visual elemento de ornamentaciâ”œâ”‚n vegetal. En los aâ”œâ–’os 60 se levantarâ”œأ­ el nuevo Instituto Femenino Miguel Servet, inaugurado en 1965, con lo que nuevamente el Botâ”œأ­nico tendrâ”œأ­ que hacer las maletas, y en 1970 recabar en el parque Primo de Rivera, en donde perma', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64993900, -0.87839100, '0101000020E61000003B394371C71BECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20553570572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20553570572.webp', 'https://www.flickr.com/photos/zaragozaantigua/20553570572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25068, 'Cristo 1978', 'Por partes: 1. A la derecha, Cristo resucitado. Se trata de una de las denominaciones dadas a un predicador judâ”œآ،o que, segâ”œâ•‘n la tradiciâ”œâ”‚n, viviâ”œâ”‚ a comienzos del siglo I d.C. y fue crucificado en Jerusalâ”œآ®n, resucitando al tercer dâ”œآ،a, debido a su carâ”œأ­cter de segunda persona de la Santâ”œآ،sima Trinidad, o sea Dios. 2. A la izquierda, el autor de la figura, Jorge Albareda Agâ”œâ•‌eras, escultor catâ”œâ”‚lico siguiendo la tradiciâ”œâ”‚n de su familia, que parte de Manuel Albareda Cantavilla en el siglo XIX. Su hijo Jorge Albareda Cubeles traslada el negocio de Caspe a Zaragoza. Sus hijos Josâ”œآ® y Joaquâ”œآ،n Albareda Piazuelo, los primeros Hermanos Albareda, se instalan en la calle Alluâ”œآ® Salvador en 1939. La empresa se denomina "El Arte Crtistiano". Miguel â”œأ¼ngel y Jorge Albareda Agâ”œâ•‌eras, hijos de Joaquâ”œآ،n, fueron los siguientes Hermanos Albareda. Teodoro Albareda Albareda, hijo de Miguel â”œأ¼ngel Albareda, cerrâ”œâ”‚ el taller en 1996. 3. El edificio del taller, que aâ”œâ•‘n subsiste demediado, es el que alberga el encuentro de la foto del creador con el Creador. Actualmente y desde 2007, es propiedad municipal. Mâ”œأ­s informaciâ”œâ”‚n: tausiet.blogspot.com.es/2016/01/el-taller-de-los-hermanos... Fuente visual: Blog "Pasiâ”œâ”‚n por Zaragoza".', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64891200, -0.87713900, '0101000020E6100000037AE1CE8511ECBFB1FD648C0FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15109558296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15109558296.webp', 'https://www.flickr.com/photos/zaragozaantigua/15109558296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25157, 'Puerta del Duque 1861', 'Alzado parcial de la Puerta del Duque de la Victoria, obra de Josâ”œآ® de Yarza Miâ”œâ–’ana, levantada en 1861 junto a la iglesia de San Miguel de los Navarros, en honor del general Baldomero Espartero. Sustituyâ”œâ”‚ a la erigida en 1856, que se habâ”œآ،a venido abajo. Permaneciâ”œâ”‚ hasta 1919. Fuente: AMZ.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64954300, -0.87616100, '0101000020E610000022FB20CB8209ECBF412C9B3924D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32044878371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32044878371.webp', 'https://www.flickr.com/photos/zaragozaantigua/32044878371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
