INSERT INTO public.photos VALUES (23652, '&quot;Castillejos&quot;, 1913', 'El domingo 23 de noviembre de 1913, hora local de las 14:45h., tuvo lugar la gran puesta de largo del nuevo movimiento "Boy-Scout" o de los "Exploradores" en la ciudad, y algo despuâ”œآ®s, entre las tapias del cuartel del 18â”¬â•‘ de caballerâ”œآ،a, أ”أ‡آ£Cazadores de los Castillejosأ”أ‡أک, consistente en el ceremonial de la Primera Promesa de los Exploradores de Zaragoza, que es considerada la primera gran escenificaciâ”œâ”‚n del movimiento scout-escultista-explorador en Aragâ”œâ”‚n. En primer plano y en la despejada "Huerta del General" del cuartel, aspecto de la disciplinada y colectiva promesa, que incluye una secciâ”œâ”‚n de velocâ”œآ،pedos, y la presencia de patrullas de Huesca y Jaca. Una vez tomada la promesa y cumplidas las fâ”œâ”‚rmulas del ritual, cantaron todos el himno de los exploradores acompaâ”œâ–’ados por la banda del regimiento de Gerona, y desfilaron despuâ”œآ®s ante la bandera nacional. Tras unas prâ”œأ­cticas consistentes en el montaje de pabellones, ejercicios de gimnasia sueca, telegrafâ”œآ،a y otras evoluciones, se llegâ”œâ”‚ al momento de la merienda, consistentes en magras con tomate. Terminâ”œâ”‚ el evento con un desfile descendente por el paseo de sagasta hasta el puente de santa Engracia sobre el râ”œآ،o Huerva. Asistieron a estos actos el capitâ”œأ­n general, el alcalde, el gobernador militar y numerosos jefes y oficiales del ejâ”œآ®rcito. Al fondo, tras los cuartelarios muros, arboles del paseo de Torrero, entre los que se deja entrever el edificio del nâ”¬â•‘ 20, que excepcionalmente supervive en nuestros dâ”œآ،as. A la derecha, fuera de plano, el denominado paseo de la Iglesia, por la neoclâ”œأ­sica de San Fernando, por donde tambiâ”œآ®n fluâ”œآ،a al aire la acequia del Plano, que poco despuâ”œآ®s abastecâ”œآ،a, en natural descenso, al lavadero de la "Balseta". A la izquierda, el paseo de la Playa, ribereâ”œâ–’o con el Canal Imperial de Aragâ”œâ”‚n.', 1913, 1913, 1913, 'Anos 10', 'TORRERO', 41.63440100, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF5CC64D0D34D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20355835826.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20355835826.webp', 'https://www.flickr.com/photos/zaragozaantigua/20355835826/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
