INSERT INTO public.photos VALUES (25412, 'Puente de San Josâ”œآ® aâ”œâ–’os 20', 'Colecciâ”œâ”‚n Alfonso Tuâ”œâ–’â”œâ”‚n. Puente de San Josâ”œآ® sobre el râ”œآ،o Huerva. A la derecha, acceso a la plaza de San Miguel; a la izquierda, comienzo del camino del Bajo Aragâ”œâ”‚n, actual Miguel Servet.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.64875400, -0.87566500, '0101000020E6100000130F289B7205ECBF1893FE5E0AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15165432462.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15165432462.webp', 'https://www.flickr.com/photos/zaragozaantigua/15165432462/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
