INSERT INTO public.photos VALUES (25439, 'Puente de San Josâ”œآ® c.1930', 'Imagen del puente de San Josâ”œآ® sobre el râ”œآ،o Huerva, como arranque de la calle de Miguel Servet. A la derecha, acceso desde el paseo de la Mina, la plaza de San Miguel, y la calle del Asalto. En el siglo XVI, la nueva y pâ”œآ®trea fâ”œأ­brica de este puente estaba ubicada unos 300 metros aguas abajo, en el principio del original camino de Bajo Aragâ”œâ”‚n, y a su vera, extramuros, fue levantado el convento de los carmelitas descalzos de San Josâ”œآ®, por lo que el "puente sobre el Huerva", el mâ”œأ­s importante sobre este râ”œآ،o en la ciudad, comenzâ”œâ”‚ a ser denominado "de San Josâ”œآ®". El de la imagen, era el puente construido en 1855, tras varios previos en madera (y en otras ubicaciones cercanas), alguno de los cuales se los llevâ”œâ”‚ por delante el Huerva en sus tremendas salidas de madre. En 1923 este puente fue ensanchado con proyecto del arquitecto Miguel â”œأ¼ngel Navarro Pâ”œآ®rez, reaprovechando la parte metâ”œأ­lica del puente de Santa Engracia al quedar â”œآ®ste soterrado por el cubrimiento de ese tramo del râ”œآ،o Huerva. A finales del siglo y principios del XXI fue objeto de mâ”œأ­s ensanches. Fuente visual: Estudio Coyne, AHPZ-DARA', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64880800, -0.87574200, '0101000020E6100000EA7937161406ECBF0CB1FA230CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26424022600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26424022600.webp', 'https://www.flickr.com/photos/zaragozaantigua/26424022600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25452, 'San Miguel c.1910', 'Imagen capturada desde el puente de San Josâ”œآ®, centrada en el entorno de la iglesia parroquial de San Miguel de los Navarros y la aislada puerta del Duque de la Victoria, aâ”œâ•‘n con las casetas del cobro de consumos. Al fondo, la plaza de San Miguel. Sobre el firme del puente, tendido tranviario de la lâ”œآ،nea del Bajo Aragâ”œâ”‚n, tambiâ”œآ®n de acceso al cocherâ”œâ”‚n de los tranvâ”œآ،as. Fuente visual: "Puerta del Duque â”œآ® Iglesia de San Miguel", postal nâ”¬â•‘ 359 de la fototipia Castaâ”œâ–’eira y â”œأ¼lvarez (Madrid) en la serie "Zaragoza", en www.ebay.es/', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.64951900, -0.87615100, '0101000020E61000003F726BD26D09ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34741543325.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34741543325.webp', 'https://www.flickr.com/photos/zaragozaantigua/34741543325/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25579, '&quot;El Tenis&quot; 1958', 'Foto Alpi. 08/12/1958. Imagen del partido de la Liga Espaâ”œâ–’ola de Baloncesto jugado entre el local C. D. Iberia y el inmaculado Real Madrid, en la cancha del R.Z.C. de Tenis. El equipo de la Villa y Corte sumâ”œâ”‚ 4 puntos mâ”œأ­s (49-53), y se llevâ”œâ”‚ la victoria. No hacâ”œآ،a demasiado fresco, el campo estaba abarrotado, y el â”œأ­rbitro no fue arbitrario. Todos contentos. Al fondo de la imagen, tras el muro, Miguel Servet. A la izquierda, edificios de vivienda de la calle Asalto, que en realidad son las traseras de los de la calle Reconquista, y que han supervivido hasta el momento. Enfrente, la enorme estructura del Garaje Solano. A la derecha, fuera de plano, el Puente de San Josâ”œآ® y el râ”œآ،o Huerva. Fuente visual: www.lacasadelbaloncesto.es/Visor.asp?id=1160&Fon=430', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64886500, -0.87608400, '0101000020E61000004B901150E108ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15481468252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15481468252.webp', 'https://www.flickr.com/photos/zaragozaantigua/15481468252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25585, 'Soto del Puente de San Josâ”œآ® 1865', 'Plano del Soto del Puente de San Josâ”œآ®, Antonio Berbegal, Zaragoza, 1865. Terrenos de soto entre el râ”œآ،o Huerva y el paseo de la Mina, dedicados a viveros municipales, luego Club de Tenis y hoy Centro de Convivencia para Mayores Pedro Laâ”œآ،n Entralgo. El puente que aparece arriba a la izquierda es una construcciâ”œâ”‚n auxiliar: el puente de San Josâ”œآ® no figura en el plano. Fuente: AMZ.', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.64871100, -0.87650300, '0101000020E61000008411FB04500CECBF19C748F608D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20846116320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20846116320.webp', 'https://www.flickr.com/photos/zaragozaantigua/20846116320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25588, 'Râ”œآ،o Huerva 1861', 'Orillas del râ”œآ،o Huerva, con el puente de San Josâ”œآ® y la iglesia de San Miguel al fondo. Fuente visual: Mariano Jâ”œâ•‘dez y Ortiz. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s. Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64910400, -0.87491600, '0101000020E61000008AE8D7D64FFFEBBFF5D901D715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27968132813.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27968132813.webp', 'https://www.flickr.com/photos/zaragozaantigua/27968132813/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25795, 'Club de Tenis 1974', 'Partido de baloncesto femenino en el Club de Tenis de Zaragoza, actual Hogar de la Tercera Edad en paseo de la Mina. Al fondo, iglesia de San Miguel. Fuente: www.facebook.com/photo.php?fbid=384157705058919&set=o...', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64877200, -0.87662600, '0101000020E610000071581AF8510DECBFBF47FDF50AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701448120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701448120.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701448120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25796, 'Puerta del Duque de la Victoria 1861', '"Puerta del Duque de la Victoria, erigida en honor del general Baldomero Espartero, y costeada a sus expensas por Juan Bruil, que se abriâ”œâ”‚ al pâ”œâ•‘blico el 5 de octubre de 1861 y que permaneciâ”œâ”‚ en pie hasta 1919. Esta puerta en hierro, fundida en Inglaterra e instalada bajo la direcciâ”œâ”‚n del arquitecto Josâ”œآ® de Yarza Miâ”œâ–’ana, sustituâ”œآ،a a la primera puerta hecha de ladrillo, que fue erigida en 1856 y que se vino abajo, poco tiempo despuâ”œآ®s, por la precipitaciâ”œâ”‚n con la que fue construida." Josâ”œآ® Antonio Hernâ”œأ­ndez Latas. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s. Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64948600, -0.87610900, '0101000020E61000008466D7BD1509ECBFDD9A745B22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710337490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710337490.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710337490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25797, 'Iglesia de San Miguel 1889', 'J. Lâ”œآ®vy et Cie, 1889 Iglesia de San Miguel de los Navarros.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64971800, -0.87633200, '0101000020E610000053060E68E90AECBFAFCF9CF529D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14805005490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14805005490.webp', 'https://www.flickr.com/photos/zaragozaantigua/14805005490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25798, 'Plaza de San Miguel c.1895', 'Imagen de la plaza de San Miguel, con detalle de la iglesia, y su torre, antes de la intervenciâ”œâ”‚n de 1898, en la que se instalâ”œâ”‚ un nuevo chapitel modernista diseâ”œâ–’ado por Ricardo Magdalena, consistente en un campanil de hierro forjado con decoraciâ”œâ”‚n floral y lineal, rematado por una aguja câ”œâ”‚nica. Fuente visual: AHPZ-Archivo Coyne.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64977100, -0.87608900, '0101000020E6100000BD546CCCEB08ECBFD27135B22BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14878507374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14878507374.webp', 'https://www.flickr.com/photos/zaragozaantigua/14878507374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25799, 'Pl. de San Miguel 1970', 'Imagen de la plaza de San Miguel desde la esquina de la calle Antonio Agustâ”œآ،n. El objetivo se centra en la iglesia de San Miguel de los Navarros. Fuente visual: Gerardo Sancho Ramo, julio 1970, AMZ', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15548327549.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15548327549.webp', 'https://www.flickr.com/photos/zaragozaantigua/15548327549/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25800, 'Iglesia de San Miguel c.1895', '"Tower of la Seo. Zaragoza", ilustraciâ”œâ”‚n para "Glories of Spain", un tanto desnortada, pues es la torre de la iglesia de San Miguel de los Navarros, en su versiâ”œâ”‚n anterior a la moderna intervenciâ”œâ”‚n de Ricardo Magdalena, en 1898. Fuente visual: Charles W. Wood, New York, 1901.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18898974593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18898974593.webp', 'https://www.flickr.com/photos/zaragozaantigua/18898974593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25802, 'Plaza de San Miguel 1987', 'Imagen de la pared medianera del nâ”¬â•‘ 4 de la calle Reconquista, antes de la intervenciâ”œâ”‚n consistente en pintar un mural representando a la antigua Puerta del Duque, que desde 1861 y hasta su derribo en 1919 estuvo en sus inmediaciones. Este medianil mostraba los inequâ”œآ،vocos signos de una continuidad constructiva de antiguas edificaciones alineadas, que recordaban la inexistencia de salida de la plaza de San Miguel hacia el sur, hasta hace no demasiado tiempo. Tras su derribo, para dar anchura al trâ”œأ­fico rodado, este medianil fue un espacio publicitario comercial, como la imagen muestra. El autor del diseâ”œâ–’o del mural fue Josâ”œآ® Lanao, y tras las obras de acondicionamiento y preparaciâ”œâ”‚n, el pintor Alfonso Forcellino fue el encargado de realizar en 1988 el moderno trampantojo de la antigua Puerta del Duque de la Victoria. Fuente visual: Democracia y pintura mural en Zaragoza 1984-1995, Rolde de estudios aragoneses, 2014.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.64957100, -0.87591200, '0101000020E61000000491459A7807ECBF0BB77C2425D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19346263443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19346263443.webp', 'https://www.flickr.com/photos/zaragozaantigua/19346263443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25804, 'Pl. de San Miguel 1971', 'Vista de la plaza e iglesia de San Miguel desde la calle de Espartero. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65005000, -0.87616000, '0101000020E61000000C0742B28009ECBFE561A1D634D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23130539855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23130539855.webp', 'https://www.flickr.com/photos/zaragozaantigua/23130539855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25805, 'Calle de San Miguel 1971', 'Calle San Miguel. A la espalda del fotâ”œâ”‚grafo, la plaza homâ”œâ”‚nima. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.64981000, -0.87698600, '0101000020E61000006C98A1F14410ECBF904E5DF92CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23140927762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23140927762.webp', 'https://www.flickr.com/photos/zaragozaantigua/23140927762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25806, 'Calle San Miguel 1836', '"Calle proyectada en la continuaciâ”œâ”‚n de la de San Miguel hasta el paseo nuevo de Santa Engracia", Josâ”œآ® de Yarza y Joaquâ”œآ،n Gironza, Zaragoza, 1836. Fuente: Evoluciâ”œâ”‚n histâ”œâ”‚rico-urbanâ”œآ،stica de la ciudad de Zaragoza, Colegio de Arquitectos de Aragâ”œâ”‚n, 1982.', 1836, 1836, 1836, 'Siglo XIX', 'CENTRO', 41.65050700, -0.87905700, '0101000020E6100000643C4A253C21ECBFD76839D043D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23832657489.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23832657489.webp', 'https://www.flickr.com/photos/zaragozaantigua/23832657489/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25807, 'San Miguel c.1895', 'Dibujo de "Saint-Michel des Navarrais" firmado por Boudier, como ilustraciâ”œâ”‚n al parisino libro "Aragon et Valence, Barcelone, Saragosse, Sagonte, Valence : les beaux-arts, les moeurs, les coutumes", de Madame Jane Dieulafoy, editado en 1901. La imagen se corresponde con el estado de la torre parroquial antes de la intervenciâ”œâ”‚n de 1898, en que se instalâ”œâ”‚ un nuevo chapitel modernista diseâ”œâ–’ado por Ricardo Magdalena. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24910482236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24910482236.webp', 'https://www.flickr.com/photos/zaragozaantigua/24910482236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25808, 'Calle San Miguel 1895', '"Vista perspectiva de la casa nâ”¬â•‘ 22 y parcela de la nâ”¬â•‘ 20 de la calle de San Miguel, contiguas al convento de Sta. Catalina, de la propiedad de D. Fâ”œآ®lix Burriel". Francisco de Paula Albiâ”œâ–’ana, Zaragoza, 26 de noviembre de 1895. Detallado dibujo que muestra la esquina de la calle de San Miguel (izquierda) con la actual del Arquitecto Magdalena, entonces aâ”œâ•‘n sin abrir. A la derecha, acceso al convento de monjas clarisas de Santa Catalina. Fuente: DARA/AHPZ.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25215948766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25215948766.webp', 'https://www.flickr.com/photos/zaragozaantigua/25215948766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25810, 'San Miguel c.1897', '"Zaragoza. Iglesia de San Miguel". Postal editada por la Fototipia de Lucas Escolâ”œأ­ hacia 1900, si bien la imagen de la iglesia parroquial de San Miguel de los Navarros, capturada desde cierta altura en la plaza de San Miguel, es anterior a la reforma de 1898, en la que se instalâ”œâ”‚ un nuevo chapitel modernista diseâ”œâ–’ado por Ricardo Magdalena. Fuente visual: www.todocoleccion.net/', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64953700, -0.87617100, '0101000020E61000000684D6C39709ECBF5F45460724D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25398540990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25398540990.webp', 'https://www.flickr.com/photos/zaragozaantigua/25398540990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25811, 'Plaza de San Miguel c.1895', 'Captura fotogrâ”œأ­fica de Marcel y Jane Dieulafoy de "Saragosse" incluida en el album "767 phot. d''Espagne, du Portugal et du Roussillon" editado en 1920, aunque con imâ”œأ­genes muy anteriores, como esta, correspondiente con la plaza de San Miguel, centrada en la iglesia parroquial antes de la intervenciâ”œâ”‚n de Ricardo Magdalena en 1898. Fuente visual: gallica.bnf.fr/', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64953700, -0.87617100, '0101000020E61000000684D6C39709ECBF5F45460724D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29118294540.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29118294540.webp', 'https://www.flickr.com/photos/zaragozaantigua/29118294540/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25812, 'Calle Asalto 1995', 'Vista de la esquina de la calle Asalto con la del Heroâ”œآ،smo, en el proceso de derribo de sus inmuebles, luego ocupados por el bloque del nâ”œâ•‘mero 23. Fuente: www.facebook.com/photo.php?fbid=1377347082278360&set=...', 1995, 1995, 1995, 'Anos 90', 'CENTRO', 41.64927900, -0.87479900, '0101000020E6100000255AF2785AFEEBBF637D03931BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30706986263.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30706986263.webp', 'https://www.flickr.com/photos/zaragozaantigua/30706986263/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25814, 'Calle del Asalto 1977', 'Imagen del primer tramo de la calle del Asalto que aquâ”œآ، incluye las traseras del nâ”¬â•‘ 2 de la calle de la Reconquista y los nâ”œâ•‘meros 1 y 3 (en una vista parcial) de la del Asalto. A la izquierda, solar resultante del derribo del ruinoso inmueble que fuera nâ”¬â•‘ 10 de la plaza de San Miguel. Los carteles pegados a la derecha se corresponden con los tradicionales espectâ”œأ­culos de las revistas que acudâ”œآ،an a la ciudad durante las fiestas del Pilar.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64951400, -0.87591200, '0101000020E61000000491459A7807ECBFA725564623D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52437729024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52437729024.webp', 'https://www.flickr.com/photos/zaragozaantigua/52437729024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25900, 'Plaza de San Miguel c.1905', 'Imagen de la puerta del Duque de la Victoria seâ”œâ–’alando el ingreso a la plaza de San Miguel desde la carretera de Zaragoza a Castellâ”œâ”‚n, tal y como estâ”œأ­ a punto de hacer por su vano central uno de los "Primitivos" tranvâ”œآ،as de la lâ”œآ،nea del Bajo Aragâ”œâ”‚n, electrificada recientemente. Al fondo, despuâ”œآ®s de la calle de Espartero, el bloque de viviendas situado justo a la derecha del Almudâ”œآ، y "las Piedras del Coso", eclipsadas de la visual por el seâ”œâ–’or que cruza. Hacâ”œآ،a algunos aâ”œâ–’os que se estaba dirimiendo el futuro de esta puerta, pues tenâ”œآ،a sus defensores, y sus detractores, sobre lo oportuno que era, o no, su mantenimiento. Unos aâ”œâ–’os despuâ”œآ®s de esta imagen (1911), el Ayuntamiento le amputarâ”œآ،a los dos pequeâ”œâ–’os ingresos laterales (parcialmente visible el de su izquierda), dejando el central. Finalmente, en abril de 1919 el gran arco central de la puerta fue tambiâ”œآ®n desmantelado, y sus restos se volatilizaron. Fuente visual: "Las puertas de la ciudad", por Lasala, Serrano, y Torrâ”œâ•‘s.', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64948600, -0.87610900, '0101000020E61000008466D7BD1509ECBFDD9A745B22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17683400330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17683400330.webp', 'https://www.flickr.com/photos/zaragozaantigua/17683400330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25930, 'Calle de Violante de Hungrâ”œآ،a 1954', 'Imagen capturada en el despejado principio de la calle de Violante de Hungrâ”œآ،a, un espacio que aâ”œâ–’os mâ”œأ­s tarde serâ”œآ،a denominado plaza del Emperador Carlos de toda la vida, y centrada en la terminal tranviaria de la lâ”œآ،nea 11 &quot;Parque&quot; allâ”œآ، ubicada, donde espera la unidad 209 para iniciar el descendente recorrido hasta la plaza de Espaâ”œâ–’a. Tras la unificaciâ”œâ”‚n con la lâ”œآ،nea 13 &quot;San Josâ”œآ®&quot; en 1967 esta unidad continuâ”œâ”‚ realizando viajes hasta 1976, cuando la lâ”œآ،nea fue clausurada y la 209 desguazada. De fondo escâ”œآ®nico, a la izquierda uno de los pabellones del cuartel de Palafox recayente a la calle de Pedro Cerbuna, y a la derecha medianera y vista parcial del grupo de viviendas de la calle del Arzobispo Apaolaza 31-39, diseâ”œâ–’ado por el arquitecto Antonio Châ”œâ”‚liz Alcrudo dentro del desarrollo urbanâ”œآ،stico del ensanche de Miralbueno. Fuente visual: Josâ”œآ® Marâ”œآ،a Valero Suâ”œأ­rez, Centenario del tranvâ”œآ،a elâ”œآ®ctrico. Zaragoza, 1902-2002.', 1954, 1954, 1954, 'Anos 50', 'UNIVERSIDAD', 41.63776300, -0.89858100, '0101000020E6100000BFD2F9F02CC1ECBFA7CCCD37A2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40480110120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40480110120.webp', 'https://www.flickr.com/photos/zaragozaantigua/40480110120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25905, 'Plaza de San Miguel 1968', 'Imagen con uno de esos zaragozanos dâ”œآ،as neblinosos en que los contornos de las cosas, a lo lejos, pierden consistencia, y se difuminan como los recuerdos. Tal que hoy. A la izquierda, al fondo, se intuye la gâ”œâ”‚tico-mudâ”œآ®jar torre, y el poligonal y cabecero â”œأ­bside principal de la iglesia parroquial de San Miguel de los Navarros. Voladizo, el tendido elâ”œآ®ctrico que garantizaba corriente continua de 600 voltios a las tranviarias lâ”œآ،neas de explotaciâ”œâ”‚n que por aquâ”œآ، prestaban servicio. Hasta su desmantelamiento en 1966, lo hizo la lâ”œآ،nea 17 ("Las Fuentes"). Desde 1967, la nueva macrolâ”œآ،nea 11 "Parque-San Josâ”œآ®" (uniâ”œâ”‚n de la 11 y la 13), ademâ”œأ­s de la composiciâ”œâ”‚n 1 ("Bajo Aragâ”œâ”‚n") + 15 ("Casablanca"), experimento que apenas durarâ”œآ،a un par de aâ”œâ–’os. Entonces, la pionera lâ”œآ،nea del "Bajo Aragâ”œâ”‚n" retomarâ”œآ،a su trazado, que comenzâ”œâ”‚ allâ”œأ­ por 1885, llegando casi a cumplir los noventa aâ”œâ–’os de servicio a la ciudad. Al final, todas fueron erradicadas para que los neumâ”œأ­ticos vehâ”œآ،culos que ruedan en la imagen, no fueran incordiados por esos malvados, medievales y molestos ingenios sobre raâ”œآ،les, y bajo trole. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.64903200, -0.87583800, '0101000020E61000007102D369DD06ECBF5B07077B13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24270528690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24270528690.webp', 'https://www.flickr.com/photos/zaragozaantigua/24270528690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25906, 'San Miguel c.1900', 'Imagen para postal de la Fototipia Hauser y Menet, de Madrid, capturando la iglesia de San Miguel de los Navarros, la Puerta del Duque de la Victoria, y una unidad de la tranviaria Lâ”œآ،nea "Bajo Aragâ”œâ”‚n" a punto de adentrarse en el tramo suburbano del recorrido, una vez cruzado el puente de San Josâ”œآ®, por la carretera de Zaragoza a Castellâ”œâ”‚n, hasta la estaciâ”œâ”‚n de ferrocarril de Cappa. Fuente visual: www.delcampe.es/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64903200, -0.87583800, '0101000020E61000007102D369DD06ECBF5B07077B13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24293549684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24293549684.webp', 'https://www.flickr.com/photos/zaragozaantigua/24293549684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25909, 'Puerta del Duque c.1905', 'Vista de la iglesia de San Miguel y la Puerta del Duque desde el arranque del puente de San Josâ”œآ®. La unidad nâ”¬â•‘ 1 de la tranviaria y electrificada lâ”œآ،nea Bajo Aragâ”œâ”‚n, rumbo a la estaciâ”œâ”‚n de Cappa, o de Utrillas. Huecograbado de la serie "Aragâ”œâ”‚n" de postales editadas por el librero Cecilio Gasca. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.64953700, -0.87617100, '0101000020E61000000684D6C39709ECBF5F45460724D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26794889254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26794889254.webp', 'https://www.flickr.com/photos/zaragozaantigua/26794889254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25921, 'Pl. de San Miguel 1969', 'Imagen capturada durante el solsticio de verano (21 de junio) en la plaza de San Miguel, y centrada en la unidad nâ”¬â•‘ 302 de la tranviaria lâ”œآ،nea 11, encaminada hacia el barrio de San Josâ”œآ®. A la izquierda, antigua y monocroma fachada del nâ”¬â•‘ 12 de la plaza, antes de ser recrecido tres alturas mâ”œأ­s. Tras el tranvâ”œآ،a, el nâ”¬â•‘ 14, que luego tambiâ”œآ®n fue elevado una planta. A la derecha, la calle de Espartero, y el Coso. Este fue el â”œâ•‘ltimo de los tranvâ”œآ،as histâ”œâ”‚ricos que circulâ”œâ”‚ por Zaragoza en 1976, hasta que en 2011 fue recuperado este modo de transporte. Fuente visual: foto Mike Cornwall, en www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64981300, -0.87633000, '0101000020E6100000261E5036E50AECBF01C287122DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32230006414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32230006414.webp', 'https://www.flickr.com/photos/zaragozaantigua/32230006414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21847, 'Madre Sacramento 1934', 'Imagen capturada en el tramo inicial de la calle de la Venerable Madre Sacramento, de moderna urbanizaciâ”œâ”‚n. A la izquierda, tras una amplia zona de huertos, anuncio comercial que seâ”œâ–’ala la ubicaciâ”œâ”‚n de los Talleres Mecâ”œأ­nicos de Reparaciâ”œâ”‚n de Automâ”œâ”‚viles Josâ”œآ® Iglesias. A la derecha, los antiguos inmuebles de los nâ”œâ•‘meros 6, 8 y 10 de la calle, tras los que se abre la calle de la Industria, en cuya esquina destaca la moderna casa y fâ”œأ­brica de gaseosas de Hermenegildo Aguaviva, con diseâ”œâ–’o de Regino Borobio. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64937200, -0.89049200, '0101000020E61000002F302B14E97EECBF1478279F1ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35669809403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35669809403.webp', 'https://www.flickr.com/photos/zaragozaantigua/35669809403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22176, 'Madre Sacramento 1951', 'Despejada imagen de la calle Madre Sacramento capturada casi desde su ingreso por la calle de Hernâ”œأ­n Cortâ”œآ®s. A la izquierda, e inmediato, el edificio del nâ”¬â•‘ 5. A la derecha, el muro que delimitaba una antigua zona de huerta junto al convento de las MM. Adoratrices, y a continuaciâ”œâ”‚n, el acceso a la calle del Capitâ”œأ­n Esponera. Hacia el fondo, la calle avanza en curva hasta desembocar en Josâ”œآ® Anselmo Clavâ”œآ®. Fuente visual: Foto Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64911600, -0.88978400, '0101000020E61000004B21904B1C79ECBFB9A7AB3B16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31558300655.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31558300655.webp', 'https://www.flickr.com/photos/zaragozaantigua/31558300655/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22208, 'P.â”¬â•‘ de Mâ”¬آ¬ Agustâ”œآ،n c.1955', 'Imagen de la clâ”œآ،nica de Nuestra Seâ”œâ–’ora del Carmen de la que era titular el doctor Ricardo Horno Alcorta, sita en el paseo de Marâ”œآ،a Agustâ”œآ،n nâ”¬â•‘ 23 (antiguo nâ”¬â•‘ 5 septuplicado), esquina con la antigua calle de la Industria (a la derecha, redenominada del Doctor Horno Alcorta tras su fallecimiento en 1948). A este edificio, en cuyas traseras se abrâ”œآ،a un notable jardâ”œآ،n interior, se le anexâ”œâ”‚ a la inmediata izquierda en 1929 la casa de nueva planta del doctor Ricardo Horno, que hasta entonces residiâ”œâ”‚ y ejerciâ”œâ”‚ en la calle de Alfonso I, y que fue diseâ”œâ–’ada por Fernando Garcâ”œآ،a Mercadal. Casa y clâ”œآ،nica fueron mâ”œأ­s tarde derribadas y en su solar fue construido un moderno y voluminoso bloque de viviendas. Fuente visual: "Mariano Horno Liria In Memoriam", La Cadiera, 2008.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65063100, -0.88965500, '0101000020E6100000D52137C30D78ECBFC36169E047D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41146665412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41146665412.webp', 'https://www.flickr.com/photos/zaragozaantigua/41146665412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22436, 'Paseo de Teruel 1965', 'Imagen capturada en el arranque del paseo de Teruel, cuando casualmente transita sobre el adoquinado pavimento el trolebâ”œâ•‘s de dos pisos "BUT", dorsal nâ”¬â•‘ 72 de la lâ”œآ،nea "Ciudad Jardâ”œآ،n", entrado en servicio apenas un par de aâ”œâ–’os antes, en su ruta hacia la terminal de la plaza de Santa Engracia. A su izquierda, la calle de Hernâ”œأ­n Cortâ”œآ®s, con el emboque a la calle de Castellvâ”œآ،, donde figuraba su antiguo y provinciano edificio esquinero. Al fondo, asoman las instalaciones del cuartel del ejâ”œآ®rcito radicado donde estuviera el Convento de los Capuchinos. Detrâ”œأ­s del trolebâ”œâ•‘s, el chaflanero y reciente nâ”¬â•‘ 1 del paseo de Teruel, sede de la agencia urbana nâ”¬â•‘ 2 del local Banco Zaragozano (que dios guarde en su gloria). Fuente visual: Vicente Modesto Locual.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.64863500, -0.88956900, '0101000020E6100000322251685977ECBF3E05C07806D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30548938871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30548938871.webp', 'https://www.flickr.com/photos/zaragozaantigua/30548938871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22495, 'Calle de la Madre Sacramento c.1961', 'Imagen capturada en el tramo de la calle de la Madre Sacramento entre las calles del Capitâ”œأ­n Casado y la del Doctor Horno, antigua de la Industria, y centrada en el reciâ”œآ®n construido inmueble del nâ”¬â•‘ 34. A su izquierda, el veterano edificio del nâ”¬â•‘ 36, y una vista parcial del antiguo nâ”¬â•‘ 38, derribado y sustituido por otro mâ”œأ­s moderno al principio del siglo XXI. A su derecha, nave posiblemente de uso industrial que aâ”œâ–’os despuâ”œآ®s serâ”œآ،a derribada para dar paso al desarrollista inmueble del nâ”¬â•‘ 32 de esta calle. En primer tâ”œآ®rmino y a la izquierda, un isocarro de transporte y su operario.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.64990700, -0.89178000, '0101000020E61000009A42E7357689ECBF82380F2730D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48232449977.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48232449977.webp', 'https://www.flickr.com/photos/zaragozaantigua/48232449977/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22578, 'Calle Castellvâ”œآ، 1970', 'Calle de Castellvâ”œآ، con el antiguo edificio de vivienda, almacâ”œآ®n y portalâ”œâ”‚n de su tramo final conducente a la calle de Hernâ”œأ­n Cortâ”œآ®s, luego sustituidos por dos modernos inmuebles. La toma se ha realizado desde la entrada a la estaciâ”œâ”‚n de autobuses a Teruel, desde 2011 reutilizada por la contratista municipal de la limpieza. Al fondo destaca el edificio que hace chaflâ”œأ­n con el paseo de Teruel, entonces ocupado como sucursal del Banco Zaragozano.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64832800, -0.88948400, '0101000020E6100000A5164A26A776ECBF618A7269FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15547985537.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15547985537.webp', 'https://www.flickr.com/photos/zaragozaantigua/15547985537/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22743, 'Hernâ”œأ­n Cortâ”œآ®s 1973', 'Tramo de la calle de Hernâ”œأ­n Cortâ”œآ®s capturado junto al despartidero donde hacia la derecha da comienzo el paseo de Teruel, que muestra el acusado contraste entre los antiguos edificios de la zona, como el esquinero con la calle de Castellvâ”œآ،, e incluso el cuartel de Hernâ”œأ­n Cortâ”œآ®s, al fondo, con el bloque del nâ”¬â•‘ 23-25 en ejecuciâ”œâ”‚n, que anuncia la nueva ortodoxia urbanâ”œآ،stica de los tiempos: mâ”œأ­s moderno, mâ”œأ­s alto, mâ”œأ­s descontextualizado.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64839400, -0.88960100, '0101000020E610000009A52F849C77ECBF19761893FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32122917224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32122917224.webp', 'https://www.flickr.com/photos/zaragozaantigua/32122917224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22798, 'Calle del Dr. Horno Alcorta 1975', 'Imagen capturada ante el nâ”¬â•‘ 18 de la adoquinada calle del Doctor Horno Alcorta, antigua de la Industria, que formaba parte de la vivienda y fâ”œأ­brica de gaseosas "El sifâ”œâ”‚n higiâ”œآ®nico" de Hermenegildo Aguaviva, diseâ”œâ–’ada por Regino Borobio en 1929, y cuyo ingreso principal estaba radicado en la inmediata calle de la Madre Sacramento, a la izquierda de la escena. En primer tâ”œآ®rmino, veterano camiâ”œâ”‚n botellero de la empresa. Tras el cierre de la fâ”œأ­brica, la parte del inmueble correspondiente a la misma (el nâ”¬â•‘ 18 de la imagen) fue derribado y sobre su solar se construyeron modernos bloques de viviendas. Los bajos que aquâ”œآ، aparecen tambiâ”œآ®n fueron luego notablemente transformados. En primer tâ”œآ®rmino, veterano camiâ”œâ”‚n botellero de la empresa, modelo Ford 1940.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64970100, -0.89079200, '0101000020E6100000D63A71395E81ECBFD996016729D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46395468091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46395468091.webp', 'https://www.flickr.com/photos/zaragozaantigua/46395468091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22869, 'Cuartel de Hernâ”œأ­n Cortâ”œآ®s aâ”œâ–’os 80', 'Edificio del cuartel de Hernâ”œأ­n Cortâ”œآ®s, prâ”œâ”‚ximo a su demoliciâ”œâ”‚n, en los aâ”œâ–’os 80 del siglo XX.', 1980, 1980, 1989, 'Anos 80', 'CENTRO', 41.64806300, -0.88999400, '0101000020E6100000F25B74B2D47AECBFB35F77BAF3D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15769068735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15769068735.webp', 'https://www.flickr.com/photos/zaragozaantigua/15769068735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23053, 'Calle de Hernâ”œأ­n Cortâ”œآ®s 1994', 'Imagen capturada durante la construcciâ”œâ”‚n del aparcamiento incluido en el gran proyecto de urbanizaciâ”œâ”‚n del espacio antes ocupado por el cuartel de Hernâ”œأ­n Cortâ”œآ®s y que en 1977 el Ayuntamiento adquiriâ”œâ”‚ por 209 millones de pesetas al ramo de la Guerra. Los 12.776 metros cuadrados de extensiâ”œâ”‚n, que originalmente se habâ”œآ،an calificado en el PGOU de 1968 como de "edificaciâ”œâ”‚n intensiva", tras la recuperaciâ”œâ”‚n de la democracia municipal dieron acogida a la Biblioteca de Aragâ”œâ”‚n de titularidad autonâ”œâ”‚mica, inaugurada en 1990, varios equipamientos municipales, como la Junta el Distrito Centro y el Centro de la Tercera Edad Francisco de Goya, el Residencial Hernâ”œأ­n Cortâ”œآ®s y una gran plaza que en 1996 serâ”œآ،a denominada de Mariano Arregui Canela, en homenaje a este cantante de jota. En la escena y a la izquierda, traseras de los inmuebles del nâ”¬â•‘ 24-26 de la calle del Doctor Cerrada. A la derecha, tramo de la calle de Hernâ”œأ­n Cortâ”œآ®s entre la de Benito Pâ”œآ®rez Galdâ”œâ”‚s y el despartidero donde arranca la calle del Carmen.', 1994, 1994, 1994, 'Anos 90', 'CENTRO', 41.64775900, -0.89012800, '0101000020E6100000DA1F28B7ED7BECBF475854C4E9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50444890623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50444890623.webp', 'https://www.flickr.com/photos/zaragozaantigua/50444890623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23216, 'Calle Cortes de Aragâ”œâ”‚n 2016', 'Septembrina y despejada imagen centrada en el no muy antiguo edificio de viviendas de planta triangular que conformaba el despartidero entre el arranque de las calles Cortes de Aragâ”œâ”‚n (izquierda) y del Carmen (derecha). Abandonado desde finales del pasado siglo XX, en el momento de capturar esta imagen el edificio (propiedad de una entidad bancaria local) estaba ya abocado hacia el derribo integral para dejar paso a un moderno inmueble con 12 viviendas, garajes, trasteros y locales comerciales que se denominarâ”œأ­ "Edificio Puerta del Carmen". Fuente visual: foto Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 2016, 2016, 2016, 'Siglo XXI', 'CENTRO', 41.64743500, -0.89105300, '0101000020E61000000516C0948183ECBF94A46B26DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41619085210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41619085210.webp', 'https://www.flickr.com/photos/zaragozaantigua/41619085210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23327, 'La Gemela del Buen Gusto 1876', '"Vista de La Gemela del Buen Gusto. Fâ”œأ­brica de chocolate y dulces con motor de vapor de Eusebio Molins. Zaragoza", dibujo para anuncio, 1876. Esta fâ”œأ­brica, puesta en marcha en 1876, se hallaba en el nâ”œâ•‘mero 228 del barrio del Castillo, direcciâ”œâ”‚n correspondiente a la carretera de Zaragoza a Valencia, hoy paseo de Teruel. Fuente: Mâ”¬آ¬ Pilar Biel Ibâ”œأ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1876, 1876, 1876, 'Siglo XIX', 'CENTRO', 41.64839900, -0.89199600, '0101000020E6100000CA3505323B8BECBF2AE109BDFED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19176154254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19176154254.webp', 'https://www.flickr.com/photos/zaragozaantigua/19176154254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24038, 'Calle de Fita 1967', 'Imagen capturada en altura de una agrupaciâ”œâ”‚n musical y artâ”œآ،stica ambulante, mientras escenificaba su actuaciâ”œâ”‚n multidisciplinar ("performance") junto al portal del nâ”¬â•‘ 19 de la calle de Bernardo Fita. Metal, percusiâ”œâ”‚n, y danza contemporâ”œأ­nea, todo por unas pocas monedas ("crowdfunding"). El arte y los proyectos creativos y cooperativos ("coworking") estâ”œأ­n en la calle desde hace tiempo. Mucho tiempo. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64690100, -0.89097600, '0101000020E61000002EABB019E082ECBFF65FE7A6CDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30145790852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30145790852.webp', 'https://www.flickr.com/photos/zaragozaantigua/30145790852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24263, 'Camino de los Cubos 1899', 'Imagen parcial del acceso principal a la fâ”œأ­brica de espejos La Veneciana, de Basilio Paraâ”œآ،so, en el camino de los Cubos, junto a la fundiciâ”œâ”‚n de Pellicer y Juan (a la izquierda, fuera de plano), y con sus traseras mirando al Huerva al aire, en el paraje denominado"curva de La Veneciana" de ese râ”œآ،o. Este edificio de 1897 posiblemente fue proyectado por Fâ”œآ®lix Navarro, y tras varios avatares. estuvo en funcionamiento hasta finales de los aâ”œâ–’os 20 del novecientos, en que la fâ”œأ­brica fue reubicada en el barrio del Castillo. Fuente visual: foto Coyne, en "Aragâ”œâ”‚n Ilustrado" nâ”¬â•‘ 2 (7 de enero de 1899).', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64608500, -0.88953700, '0101000020E61000005A9F724C1677ECBFD4B7CCE9B2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062656580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062656580.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062656580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24266, 'C.â”¬â•‘ de los Cubos 1932', 'Imagen capturada en el tramo medio del camino de los Cubos, entre la calle de Fita, cuyo arranque queda a la izquierda, y la fâ”œأ­brica de materiales de precisiâ”œâ”‚n geogrâ”œأ­fica de Laguna de Rins. En primer plano, al aire, el brazal bajo de la acequia de la Romareda. Este escenario, en pleno centro de la ciudad, resultaba antiestâ”œآ®tico, insalubre, y bien poco acorde con la categorâ”œآ،a socioeconâ”œâ”‚mica de los propietarios de la zona, que no podâ”œآ،an revalorizar adecuadamente los terrenitos de los aledaâ”œâ–’os mientras el Ayuntamiento no urbanizara este vial. Fuente visual: www.mecd.gob.es/.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.64655800, -0.88974100, '0101000020E610000079211D1EC278ECBFCC7B9C69C2D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35752448555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35752448555.webp', 'https://www.flickr.com/photos/zaragozaantigua/35752448555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24434, 'Trinitarios Descalzos 1712', 'Localizaciâ”œâ”‚n en el plano de Zaragoza de 1712 del convento de los Trinitarios descalzos en su ubicaciâ”œâ”‚n junto al paseo de San Jerâ”œâ”‚nimo o de la Ronda, el paseo de los Trinitarios y un brazal de la acequia de la Romareda.', 1712, 1712, 1712, 'Siglo XIX', 'CENTRO', 41.65103800, -0.89067500, '0101000020E610000071AC8BDB6880ECBF043A933655D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54388054248.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54388054248.webp', 'https://www.flickr.com/photos/zaragozaantigua/54388054248/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24484, 'Galletas La Universal c.1925', 'Lateral de una caja metâ”œأ­lica de galletas "La Universal. Grandes Fabricantes de Galletas, Gaufrettes, Bizcochos", propiedad de Josâ”œآ® Marâ”œآ،a Azanza y sita en la calle de Antonio Câ”œأ­novas 14 y 16, cuya fâ”œأ­brica se reproduce en el dibujo. Aâ”œâ–’os mâ”œأ­s tarde, la fâ”œأ­brica continuâ”œâ”‚ como propiedad de Doroteo Asâ”œآ،n, hasta su derribo y conversiâ”œâ”‚n en bloques de viviendas. Fuente visual: www.todocoleccion.net', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.64810200, -0.89142700, '0101000020E61000003EAF78EA9186ECBF713C9F01F5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23644158804.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23644158804.webp', 'https://www.flickr.com/photos/zaragozaantigua/23644158804/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24533, 'Calle del Doctor Cerrada c.1950', 'Insâ”œâ”‚lita vista de la fâ”œأ­brica de Laguna de Rins inaugurada en 1880 en el camino de los Cubos. En la imagen, la factorâ”œآ،a aparece flanqueada en primer tâ”œآ®rmino por el cuartel de Hernâ”œأ­n Cortâ”œآ®s, y por el inmueble del nâ”¬â•‘ 2 de la calle de Bernardo Fita. Al fondo, el esquinero inmueble del nâ”¬â•‘ 1 de esa calle. La estrecha calle del Doctor Cerrada mantiene algâ”œâ•‘n tramo al aire de la acequia de la Romareda, a la izquierda, junto a los muros perimetrales del gran recinto donde estuviera la fâ”œأ­brica de cristal de La Veneciana.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64672400, -0.88969900, '0101000020E6100000BE1589096A78ECBFE7C41EDAC7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49806577023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49806577023.webp', 'https://www.flickr.com/photos/zaragozaantigua/49806577023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25462, 'Cuartel de Hernâ”œأ­n Cortâ”œآ®s 1861', 'Cuartel de Hernâ”œأ­n Cortâ”œآ®s, al sur de la puerta del Carmen, junto al camino de Herederos. Imagen capturada desde la carretera de Valencia. Aquâ”œآ، estuvo el antiguo convento extramuros de San Juan Bautista de los PP. Capuchinos, destruido en 1808, desamortizado, y reedificado a mediados de siglo, en una parte del extenso perâ”œآ،metro conventual, ya como cuartel de infanterâ”œآ،a, tal y como sucediâ”œâ”‚ con otros antiguos conventos de la ciudad. Fuente visual: Mariano Jâ”œâ•‘dez y Ortiz. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s. Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64770700, -0.88982300, '0101000020E6100000C25087156E79ECBFF4311F10E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710617658.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710617658.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710617658/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25474, 'Convento Capuchinos 1808', '"Prise du Couvent des Capucins". Versiâ”œâ”‚n coloreada del dibujo de Karl Girardet grabado por Paul Girardet, incluido en "Histoire du Consulat et de l''Empire, faisant suite a l''Histoire de la Râ”œآ®volution Franâ”œآ؛aise", de Adolphe Thiers, Paulin (Paris), 1845-1862. Representaciâ”œâ”‚n de la toma por el ejâ”œآ®rcito francâ”œآ®s del convento de los Capuchinos en julio de 1808. Este convento, dedicado a San Juan Bautista, fue construido en 1598, reedificado en 1830, desamortizado en 1835 y reutilizado como cuartel de infanterâ”œآ،a Hernâ”œأ­n Cortâ”œآ®s, en el nâ”œâ•‘mero 33 de la actual calle homâ”œâ”‚nima, hoy plaza de Mariano Arregui y alrededores. Fuente visual: www.jeanlannes.com/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64772500, -0.89014000, '0101000020E6100000EB909BE1067CECBF9BE61DA7E8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27895969903.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27895969903.webp', 'https://www.flickr.com/photos/zaragozaantigua/27895969903/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25477, 'Calle Cortes de Aragâ”œâ”‚n 1951', 'Imagen tomada desde la calle de Hernâ”œأ­n Cortâ”œآ®s (con su cuartel homâ”œâ”‚nimo a la izquierda). En el centro, edificio que hace chaflâ”œأ­n entre las calles de las Cortes de Aragâ”œâ”‚n (izquierda) y del Carmen (derecha). Fuente: Archivo Mora. Ayuntamiento de Zaragoza.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.64743500, -0.89105300, '0101000020E61000000516C0948183ECBF94A46B26DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29857214426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29857214426.webp', 'https://www.flickr.com/photos/zaragozaantigua/29857214426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20973, 'Santa Engracia 1808', '"Explosiâ”œâ”‚n de la Iglesia de Sante Engracia en el dâ”œآ،a 4 de Agosto de 1808 de resultas de haberla minado los Franceses", Serie Ruinas de Zaragoza, de Juan Gâ”œأ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œأ­diz, 1812. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64884800, -0.88284400, '0101000020E6100000CC086F0F4240ECBF9A0986730DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19364883560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19364883560.webp', 'https://www.flickr.com/photos/zaragozaantigua/19364883560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20982, 'Convento de Santa Engracia 1854', '"Ruinen des Klosters Santa Engracia (Saragofsa)", xilografâ”œآ،a reproduciendo un grabado, Jugendfr, 1854. Fuente: AMZ.', 1854, 1854, 1854, 'Siglo XIX', 'CENTRO', 41.64880900, -0.88217800, '0101000020E6100000A305685BCD3AECBFDC2C5E2C0CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21019239776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21019239776.webp', 'https://www.flickr.com/photos/zaragozaantigua/21019239776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20987, 'Receptio animae 1890', '"Sarcâ”œâ”‚fago de Santa Engracia en Zaragoza. Tomado al natural por Anselmo Gascâ”œâ”‚n de Gotor". Dibujo de uno de los dos sarcâ”œâ”‚fagos paleocristianos del siglo IV presentes en la cripta de las Santas Masas de la iglesia de Santa Engracia. â”œأ«ste es el denominado "Receptio animae". debido a que en su centro aparece una figura femenina cuya mano es agarrada por otra que surge de arriba. Fuente: "Revue de l''art chrâ”œآ®tien", a travâ”œآ®s de www.flickr.com/photos/internetarchivebookimages/14773440465/', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64884800, -0.88284400, '0101000020E6100000CC086F0F4240ECBF9A0986730DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24545171524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24545171524.webp', 'https://www.flickr.com/photos/zaragozaantigua/24545171524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21017, 'Puerta de Santa Engracia 1860', '"Arco del triunfo erigido en la puerta de Santa Engracia (Zaragoza)". Mientras se estaba tratando de convertir la Puerta de Santa Engracia en un arco de triunfo, el anuncio de la visita de la reina Isabel II obligâ”œâ”‚ a recurrir a la simulaciâ”œâ”‚n de lienzos pintados encima para dar la apariencia de lo que no habâ”œآ،a. Asâ”œآ،, en la imagen, la puerta-trampantoja vista desde el Salâ”œâ”‚n de Santa Engracia, con visual por el vano central de la reciente estatua a Ramâ”œâ”‚n Pignatelli en la Glorieta de su nombre. Este grabado apareciâ”œâ”‚ en la revista "El Museo Universal" en su nâ”œâ•‘mero 49 (02-XII-1860). En la pâ”œأ­gina del Ministerio de Cultura en la que se encuentra, estâ”œأ­ incorrectamente datada como "nâ”¬â•‘ 42 (14-X-1860)", ya que fue en ese nâ”œâ•‘mero en el que se publicâ”œâ”‚ la breve reseâ”œâ–’a de su paso por Zaragoza el 7 de octubre de ese aâ”œâ–’o, aunque las ilustraciones, tanto esta de la Puerta de Santa Engracia, como la del "Templete levantado en la Calle del Coso", aparecieron luego en el nâ”œâ•‘mero reseâ”œâ–’ado de diciembre. Fuente visual: www.mecd.gob.es/', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64900800, -0.88419600, '0101000020E6100000E620E868554BECBFD36BB3B112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19459028853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19459028853.webp', 'https://www.flickr.com/photos/zaragozaantigua/19459028853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21018, 'Santa Engracia 1867', '"Ruinas de la iglesia de Santa Engracia", xilografâ”œآ،a de Tomâ”œأ­s Carlos Capuz incluida en la Crâ”œâ”‚nica general de Espaâ”œâ–’a, Madrid, 1867. Portada de la iglesia de Santa Engracia de Zaragoza antes de su restauraciâ”œâ”‚n en 1899. Se observa la torre desmochada en 1809 y el Cuartel de Infanterâ”œآ،a anexo.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.64908500, -0.88268800, '0101000020E6100000F14A92E7FA3EECBF7EA99F3715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19527548182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19527548182.webp', 'https://www.flickr.com/photos/zaragozaantigua/19527548182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21026, 'Santa Engracia 1860', '"Zaragoza: fachada principal de Santa Engracia", fotografâ”œآ،a capturada durante la visita oficial de la reina Isabel II a la ciudad. Frente a la fachada de la iglesia del antiguo Real monasterio, restos de la vegetal ornamentaciâ”œâ”‚n impostada para engalanar la ocasiâ”œâ”‚n, ademâ”œأ­s de la habitual garita de guardia del inmediato cuartel de Santa Engracia (a la izquierda, fuera de plano). Fuente: Charles Clifford , en Biblioteca Nacional de Espaâ”œâ–’a', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64906300, -0.88288500, '0101000020E61000007120240B9840ECBF9605137F14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22427135050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22427135050.webp', 'https://www.flickr.com/photos/zaragozaantigua/22427135050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21044, 'Puerta de Santa Engracia 1860', 'Dibujo firmado por el arquitecto Federico Inguenza Castellanos que resultâ”œâ”‚ ganador del concurso nacional convocado en 1859 para finalizar la Puerta de Santa Engracia iniciada en 1830 e inacabada desde entonces. Se trata de una simbiosis entre la funcional puerta y un monumento a la memoria de los "hâ”œآ®roes" de 1808-1809, aunque este proyecto tampoco transitâ”œâ”‚ la frontera entre las musas y el teatro, y cuando la reina Isabel II visitâ”œâ”‚ Zaragoza ese aâ”œâ–’o se hubo de cubrir con lienzos pintados a modo de trampantojo para simular que estaba terminada. Finalmente, en 1865 se demoliâ”œâ”‚ la estructura inacabada de esta "segunda" Puerta de santa Engracia.', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64894200, -0.88433500, '0101000020E61000003FA9F6E9784CECBF1B800D8810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52255522959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52255522959.webp', 'https://www.flickr.com/photos/zaragozaantigua/52255522959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21067, 'Plaza de Santa Engracia  c.1878', '"Fachada de la Iglesia de Santa Engracia". Imagen de la plaza de Santa Engracia. A la izquierda, el Cuartel de Infanterâ”œآ،a de Santa Engracia, adosado a la portada de la Iglesia del mismo nombre. A la derecha, muro y acceso a la cripta del pozo de las reliquias. Al fondo, sobresalen â”œأ­rboles del Paseo de la Mina. Fuera de plano, justo al lado y hacia la derecha, ese mismo aâ”œâ–’o de 1878 serâ”œأ­ inaugurado el Teatro Pignatelli. A la espalda del fotâ”œâ”‚grafo, la manzana de viviendas que albergâ”œâ”‚, en el palacete del barâ”œâ”‚n de la Rosa, la Capitanâ”œآ،a General de la Regiâ”œâ”‚n Militar desde 1867 a 1888, en su â”œâ•‘ltima ubicaciâ”œâ”‚n itinerante antes de recaer definitivamente en el edificio de la Glorieta de Pignatelli. Entre 1891 y 1899, Mariano Lâ”œâ”‚pez le darâ”œآ،a un nuevo aire a la iglesia de Santa Engracia, incluyendo la torre que falta en la imagen. El Cuartel de Santa Engracia serâ”œآ،a piqueteado en 1906, y parte de sus terrenos formarâ”œآ،an parte del recinto ferial de la Expo 1908. Fuente visual: Archivo Ruiz Vernacci, Foto: Jean Laurent. 1863-1880.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64908500, -0.88268800, '0101000020E6100000F14A92E7FA3EECBF7EA99F3715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17081234980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17081234980.webp', 'https://www.flickr.com/photos/zaragozaantigua/17081234980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21095, 'Plaza de Santa Engracia 1889', 'Imagen tomada en la plaza de Santa Engracia y centrada en la fachada de la iglesia homâ”œâ”‚nima, a cuya izquierda queda adosado el conjunto de edificaciones que formaban parte del cuartel tambiâ”œآ®n denominado de Santa Engracia y que acogâ”œآ،a el regimiento de infanterâ”œآ،a "Aragâ”œâ”‚n" nâ”¬â•‘ 21.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64910600, -0.88288600, '0101000020E6100000871403249A40ECBF96D1C8E715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14772661529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14772661529.webp', 'https://www.flickr.com/photos/zaragozaantigua/14772661529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21106, 'Santa Engracia 1889', '"Saragosse. Ruines de l''ancien convent de Santa Engracia". Fuente: J. Lâ”œآ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64906300, -0.88288500, '0101000020E61000007120240B9840ECBF9605137F14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22104753273.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22104753273.webp', 'https://www.flickr.com/photos/zaragozaantigua/22104753273/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21119, 'Teatro Pignatelli 1880', 'Imagen del interior del Teatro Pignatelli, esquinero entre la calle de la Independencia y la plaza de Santa Engracia, construido como teatro de verano en materiales potencialmente poco duraderos, aunque alcanzâ”œâ”‚ los cuarenta aâ”œâ–’os de servicio. Fue asâ”œآ، denominado por la influencia de la cercana estatua a Ramâ”œâ”‚n Pignatelli que presidâ”œآ،a la glorieta que se abrâ”œآ،a en el â”œâ•‘ltimo tramo de la calle de la Independencia. El escenario, al fondo, estaba orientado hacia el suroeste. Fuente visual: Foto Estudio Coyne, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.64914000, -0.88337800, '0101000020E61000003C3080F0A144ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30862758614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30862758614.webp', 'https://www.flickr.com/photos/zaragozaantigua/30862758614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21122, 'Calle de la Independencia 1880', 'Imagen del Teatro de Pignatelli, construido en 1878 bajo la direcciâ”œâ”‚n del arquitecto Fâ”œآ®lix Navarro. La captura fotogrâ”œأ­fica ha sido realizada desde cierta altura, lo que permite una interesante visual, en primer tâ”œآ®rmino, del andador central de la calle de la Independencia, arbolada y con bancos, y luego de las escalerillas por las que bajar desde esa calle hasta la plaza de Santa Engracia, a la izquierda. Unas leves vallas atemperan posibles riesgos de caâ”œآ،das a distinto nivel. Al fondo, a la derecha, el colegio del Salvador, al otro lado del râ”œآ،o Huerva. Fuente visual: Foto Venancio Villas Langa, AHPZ.', 1880, 1880, 1880, 'Siglo XIX', 'CENTRO', 41.64914000, -0.88337800, '0101000020E61000003C3080F0A144ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31588067501.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31588067501.webp', 'https://www.flickr.com/photos/zaragozaantigua/31588067501/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21147, 'Jardinera veloz en Independencia c.1890', 'La imagen se corresponde con una de las cinco unidades "jardinera" del cuarto ramal del tranvâ”œآ،a (Torrero), inaugurado en 1886, con salida en el Salâ”œâ”‚n de Santa Engracia (luego calle de la Independencia , y despuâ”œآ®s Paseo) junto a la calle Câ”œأ­diz, hasta la Playa de Torrero (hoy Barrio San Josâ”œآ®). Circula en direcciâ”œâ”‚n a Torrero en la confluencia del Salâ”œâ”‚n de Santa Engracia con un vial que en 1923 recibirâ”œأ­ el nombre de "Albareda". El edificio de viviendas de la derecha, en cuyos bajos estaba el "Cafâ”œآ® Ambos Mundos", susbiste modificado por una reforma de 1928. El edificio de la izquierda era uno de los hotelitos del entorno de la Glorieta de Pignatelli (luego Plaza de Aragâ”œâ”‚n). Serâ”œأ­ piqueteado a finales del siglo XX. "Veloz Sport" era la denominaciâ”œâ”‚n de uno de los clubs velocipâ”œآ®dicos de la ciudad, ademâ”œأ­s de la "Sociedad de Velocipedistas de Zaragoza" (en su sede del Paseo de la Lealtad, luego de Pamplona).', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64901700, -0.88447400, '0101000020E61000009831056B9C4DECBF26C632FD12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15233478180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15233478180.webp', 'https://www.flickr.com/photos/zaragozaantigua/15233478180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21153, 'Calle Independencia ca. 1899', 'Cruza la calle de la Independencia un desfile militar proveniente del Parque de Ingenieros, y marcha al Cuartel de Santa Engracia por la calle de Bruil y la de Ronda. El abanderado, como imâ”œأ­n de criaturas inconscientes. A la derecha, el antiguo palacete del barâ”œâ”‚n de la Rosa, que fuera en parte sede de la Capitanâ”œآ،a General de 1867 a 1888, y el enorme Teatro Pignatelli. Ambos edificios conformaban, por aquel entonces, buena parte de la plaza de Santa Engracia. Fuente visual: Archivo familiar Gâ”œâ”‚mez Laguna, en "El libro de oro de Aragâ”œâ”‚n", EPA, 1997.', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18762759084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18762759084.webp', 'https://www.flickr.com/photos/zaragozaantigua/18762759084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
